window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q07"]=window.__LIBQ["tien-nghich"]["q07"]||{};window.__LIBQ["tien-nghich"]["q07"]["techniques"]={"updatedAt":"2026-07-06","count":167,"techniques":[{"id":"that-tinh-kiem-tran","name":"Thất Tinh kiếm trận","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm trận","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm"],"blurb":"Kiếm trận do Vương Lâm điều động để vây công Liễu Mi. Bảy đạo kiếm khí gào thét xông ra, phối hợp với Tịch Diệt chỉ ép nàng vào thế nguy hiểm.","detail":"Trong trận với Liễu Mi, Vương Lâm dùng Thất Tinh kiếm trận bao vây nàng. Kiếm trận phát ra bảy đạo kiếm khí, phối hợp với Tịch Diệt chỉ và các thần thông khác để áp đảo phòng ngự của Liễu Mi.","nguon":["@c0635"]},{"id":"nguyen-than-loi-uy-chi","name":"Nguyên thần lôi uy chỉ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"lôi uy nguyên thần","soHuu":["Vương Lâm"],"blurb":"Một chỉ do Vương Lâm phân ra nguyên thần lôi uy ngưng tụ. Hắn định dùng đòn này lấy mạng Liễu Mi khi sát ý đã đạt cực điểm.","detail":"Vương Lâm phân ra nguyên thần lôi uy, ngưng tụ tại đầu ngón tay để thi triển một chỉ đoạt mạng Liễu Mi. Đòn này xuất hiện ở thời khắc Liễu Mi đã bị áp chế, trước khi Huyễn gia Lão Tổ mở lốc xoáy cứu nàng.","nguon":["@c0635"]},{"id":"kiem-khi-cua-lang-thien-hau","name":"Kiếm khí của Lăng Thiên Hầu","cn":"","loai":"than-thong","loaiLabel":"Kiếm khí","phamCap":"không rõ","hePhai":"kiếm đạo","soHuu":["Vương Lâm"],"blurb":"Đạo kiếm khí Vương Lâm ngưng tụ và phóng vào lốc xoáy để truy kích Huyễn gia Lão Tổ. Uy lực của nó khiến lốc xoáy sụp đổ và làm đối phương phát ra tiếng kêu đau.","detail":"Sau khi Huyễn gia Lão Tổ cứu Liễu Mi qua lốc xoáy, Vương Lâm phóng kiếm khí của Lăng Thiên Hầu vào bên trong. Kiếm khí truy kích xuyên qua lối cứu viện, đánh sụp lốc xoáy và chấn động tới nơi Huyễn gia Lão Tổ đang bế quan ở Nhà Tổ Huyễn gia trên Thiên Huyễn Tinh.","nguon":["@c0635"]},{"id":"nguyen-than-xuat-khieu","name":"Nguyên thần xuất khiếu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Huyễn gia","soHuu":["Huyễn gia Lão Tổ"],"blurb":"Thần thông giúp Huyễn gia Lão Tổ dùng nguyên thần vượt qua tinh không để cứu Liễu Mi.","detail":"Trong lần cứu Liễu Mi, Huyễn gia Lão Tổ xuất nguyên thần vượt tinh không. Trạng thái này khiến lão phải trực tiếp đối diện kiếm khí truy kích của Lăng Thiên Hầu và buộc phải bỏ chạy về mật thất Huyễn gia.","nguon":["@c0636"]},{"id":"cam-che-phong-an","name":"Cấm chế phong ấn","cn":"","loai":"khac","loaiLabel":"Cấm pháp","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Cấm pháp Vương Lâm dùng để thu nhỏ và phong ấn màn sương đen chứa oán anh Bình nhi.","detail":"Vương Lâm bấm quyết tạo từng đạo cấm khí bao quanh màn sương đen, thu nhỏ oán anh đang truyền oán khí vào người hắn rồi đưa vào Thiên nghịch không gian để tạm thời trấn giữ.","nguon":["@c0637"]},{"id":"nguyen-than-loi-uy","name":"Nguyên thần lôi uy","cn":"","loai":"than-thong","loaiLabel":"Năng lực nguyên thần","phamCap":"Không rõ","hePhai":"Lôi lực của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Lôi uy trong nguyên thần của Vương Lâm có thể quét sạch oán khí xâm nhập từ oán anh.","detail":"Khi oán khí tích tụ nhiều năm từ Bình nhi chui vào cơ thể Vương Lâm, lôi uy của nguyên thần hắn chỉ cần quét qua là có thể thanh trừ, khiến oán khí không gây ảnh hưởng đáng kể.","nguon":["@c0637"]},{"id":"dao-hoa-hoang-tuyen","name":"Đạo hóa Hoàng Tuyền","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thần thông của Vương Lâm dẫn động linh khí thiên địa và linh mạch tan vỡ, tạo Hoàng Tuyền để trợ Tôn Tích khôi phục tu vi.","detail":"Ở Nhiễm Vân Tinh, Vương Lâm thi triển Đạo hóa Hoàng Tuyền, dẫn linh khí thiên địa cùng linh lực từ các linh mạch dưới đất vào dòng Hoàng Tuyền, làm nền cho Hoàng Tuyền lực và dược lực Bát phẩm đan dược hỗ trợ Tôn Tích thổ nạp.","nguon":["@c0637"]},{"id":"hoang-tuyen-luc","name":"Hoàng Tuyền lực","cn":"","loai":"than-thong","loaiLabel":"Thức thần thông","phamCap":"Thức thứ ba của Đạo hóa Hoàng Tuyền","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thức thứ ba của Đạo hóa Hoàng Tuyền, tạo lực hút mạnh trong Hoàng Tuyền để gom linh khí cho Tôn Tích thổ nạp.","detail":"Vương Lâm gọi ra Hoàng Tuyền lực, dùng lực hút cực lớn hấp thu linh khí từ các linh mạch tan vỡ dưới đất, khiến Tôn Tích tiến vào trong Hoàng Tuyền thổ nạp và khôi phục tu vi.","nguon":["@c0637"]},{"id":"than-thong-tach-nguyen-than-cua-trieu-truyen-van","name":"Thần thông tách nguyên thần của Triệu Truyền Văn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Triệu Truyền Văn","soHuu":["Triệu Truyền Văn"],"blurb":"Thần thông được Tôn Tích nhắc tới, giúp Triệu Truyền Văn tách nguyên thần dù không luyện ra phân thân.","detail":"Tôn Tích nói Triệu Truyền Văn không luyện được phân thân nhưng có một loại thần thông giúp tách nguyên thần, nhờ đó có thể đã rời khỏi Nhiễm Vân Tinh từ trước.","nguon":["@c0637"]},{"id":"huyen-gia-ho-toc-dai-tran","name":"Huyễn gia hộ tộc đại trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Hộ tộc đại trận","hePhai":"Huyễn gia","soHuu":["Huyễn gia"],"blurb":"Đại trận bảo hộ Huyễn gia ở phía Nam Thiên Huyễn Tinh. Trận được Huyễn Vô Tình mở để chống Vương Lâm và có thể hấp thu các đạo lôi đình đầu tiên do Lôi Thú dẫn xuống.","detail":"Huyễn gia hộ tộc đại trận bao phủ khu vực phía Nam Thiên Huyễn Tinh, nơi Nhà Tổ Huyễn gia tọa lạc. Khi Vương Lâm tới đòi giao Liễu Mi, Huyễn Vô Tình dựa vào đại trận để thách hắn phá trận; các lôi đình đầu tiên của Lôi Thú rơi xuống đều bị đại trận hấp thu.","nguon":["@c0638"]},{"id":"dao-than-thong-trong-ngoc-gian-ho-toc-huyen-gia","name":"Đạo thần thông trong ngọc giản hộ tộc Huyễn gia","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Truyền thừa tiên nhân","hePhai":"Huyễn gia","soHuu":["Huyễn gia"],"blurb":"Thần thông do tiên nhân Huyễn gia lưu lại trong ngọc giản hộ tộc. Đây là một trong các chỗ dựa giúp Huyễn gia giữ vị trí thứ hai trên Thiên Huyễn Tinh.","detail":"Đạo thần thông này nằm trong ngọc giản hộ tộc do tiên nhân Huyễn gia để lại. Chương chỉ nêu đây là truyền thừa khiến Huyễn gia được kiêng kị, chưa mô tả cụ thể uy lực khi thi triển.","nguon":["@c0638"]},{"id":"phu-van-loi-phap-cua-thien-quy-tu","name":"Phù văn lôi pháp của Thiên Quỳ Tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông lôi pháp","phamCap":"Âm Hư tu sĩ thi triển","hePhai":"Thiên gia","soHuu":["Thiên Quỳ Tử"],"blurb":"Lôi pháp do Thiên Quỳ Tử dùng khi giao chiến với Tiên vệ khôi lỗi. Lão tạo lượng lớn phù văn, khiến chúng hóa lôi quang và Thiên lôi đánh xuống mục tiêu.","detail":"Trong trận chặn Vương Lâm, Thiên Quỳ Tử dùng phù văn bao phủ chiến trường rồi chuyển chúng thành lôi quang và tiếng sấm, ép Tiên vệ khôi lỗi vào thế chịu công kích. Khi Xạ Thần xa hóa Lôi Thú xuất hiện, lôi phù văn bị Lôi Thú khống chế và nuốt mất.","nguon":["@c0638"]},{"id":"kim-than-cong-kich-cua-tien-ve","name":"Kim thân công kích của Tiên vệ","cn":"","loai":"than-thong","loaiLabel":"Khả năng khôi lỗi","phamCap":"Thân thể khôi lỗi Âm Hư","hePhai":"Tiên vệ khôi lỗi","soHuu":["Tiên vệ"],"blurb":"Khả năng chiến đấu bằng thân thể của Tiên vệ khôi lỗi. Tiên vệ vận kim quang khắp thân, hóa thành kim nhân và dùng quyền lực phá phù văn của Thiên Quỳ Tử.","detail":"Tiên vệ do Tiên Đế Thanh Lâm phỏng theo Cổ Thần luyện chế, phần lớn sức mạnh nằm ở cường độ thân thể. Trong chương này, Tiên vệ lao ra, kim quang phủ toàn thân và tung quyền khiến nhiều phù văn của Thiên Quỳ Tử sụp đổ.","nguon":["@c0638"]},{"id":"mo-phong-an-loi-thu","name":"Mở phong ấn Lôi Thú","cn":"","loai":"bi-thuat","loaiLabel":"Thao tác phong ấn","phamCap":"Liên quan Xạ Thần xa","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thao tác Vương Lâm dùng để giải phóng lôi uy của Lôi Thú. Hắn nhỏ máu lên mi tâm Lôi Thú và ra lệnh mở phong ấn, khiến lôi điện bùng phát thành lốc và lưới sấm.","detail":"Khi lôi đình đầu tiên bị Huyễn gia hộ tộc đại trận hấp thu, Vương Lâm dùng máu nhỏ lên mi tâm Lôi Thú rồi mở phong ấn. Sau đó lôi uy trên thân Lôi Thú bùng lên, kéo theo mây lôi, lốc lôi điện và lưới lôi đình bên ngoài thân thể nó.","nguon":["@c0638"]},{"id":"loi-than-thong-loi-uy","name":"Lôi thần thông / lôi uy","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Lôi hệ","soHuu":["Xạ Thần xa"],"blurb":"Lôi điện do Lôi Thú phát ra trong lúc công kích Huyễn gia đại trận, khiến tộc nhân Huyễn gia đặc biệt kính sợ.","detail":"Trong trận công kích Huyễn gia, Lôi Thú dồn lôi điện tới cực hạn, tạo uy áp bao phủ phạm vi trăm dặm. Tộc nhân Huyễn gia nhận ra thân phận Lôi Thú và liên hệ của nó với Lôi Tiên Điện nên càng hoảng sợ trước lôi uy này.","nguon":["@c0639"]},{"id":"quy-tac-luc","name":"Quy tắc lực","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Khái niệm tu đạo / lực quy tắc","phamCap":"Liên quan bước thứ hai của tu đạo","hePhai":"Tu đạo bước thứ hai","soHuu":["Vương Lâm"],"blurb":"Quy tắc lực là tầng lực lượng được Thiên Quỳ Tử liên hệ với tu đạo bước thứ hai. Một kiếm Trảm La Quyết của Vương Lâm bị nhận định là ẩn chứa quy tắc.","detail":"Trong lúc quan sát trận chiến Huyễn gia, Thiên Quỳ Tử cho rằng một kiếm của Vương Lâm có quy tắc, vượt khỏi phạm vi thông thường của bước thứ nhất. Nhận định này khiến hắn nghi ngờ Vương Lâm có liên quan Lôi Tiên Điện.","nguon":["@c0640"]},{"id":"than-thong-cua-phuc-trach-ngoc-gian","name":"Thần thông của Phúc Trạch ngọc giản","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Tiên pháp / vật truyền thừa","phamCap":"Tiên pháp trong chí bảo Huyễn gia","hePhai":"Huyễn gia","soHuu":["Huyễn Vô Tình"],"blurb":"Thần thông do Phúc Trạch ngọc giản phát động khi Huyễn Vô Tình bấm quyết điều khiển. Ngọc giản hóa thành bóng người tỏa tiên lực khổng lồ để tấn công Vương Lâm.","detail":"Sau khi được Huyễn Vô Tình mời ra, Phúc Trạch ngọc giản hóa thành bóng người và bước về phía Vương Lâm. Tiên lực từ bóng người này nồng đậm đến mức áp chế linh lực trên Thiên Huyễn Tinh, buộc Tiên vệ khôi lỗi và Lôi Thú lập tức hộ bên Vương Lâm.","nguon":["@c0640"]},{"id":"lac-an-khong-che-tan-ma","name":"Lạc ấn khống chế Tán Ma","cn":"","loai":"than-thong","loaiLabel":"Thần thông/ấn ký","phamCap":"Không rõ","hePhai":"Liên quan Vương Lâm và Cổ Yêu Bối La","soHuu":["Vương Lâm"],"blurb":"Ấn ký khống chế mà Vương Lâm khắc sâu vào ma hồn Tán Ma trong hơn trăm năm. Vì có thêm thần thông của Cổ Yêu Bối La, lạc ấn này khiến Tán Ma khó phá bỏ trong thời gian ngắn.","detail":"Lạc ấn được dùng để ràng buộc Tán Ma, vốn là nền tảng khiến Vương Lâm có thể gọi Tán Ma ra trong trận tại Thiên Huyễn Tinh. Tán Ma từng nghĩ chiếm thân thể Vương Lâm, nhưng bị lạc ấn ngăn lại; nó chấp nhận giao dịch vì hy vọng sau khi được tự do sẽ mất vài trăm năm khu trừ thần thông của Bối La.","nguon":["@c0641"]},{"id":"hoa-tien-thuat","name":"Hoá Tiên Thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Một chi nhánh Cổ Yêu bộ tộc","soHuu":["hư ảnh Tiên nhân"],"blurb":"Thần thông rút linh khí toàn Thiên Huyễn Tinh, chuyển hóa thành tiên lực và ngưng tụ thành vụ cầu màu trắng ngà. Tán Ma nhận ra đây là thủ đoạn thuộc một chi nhánh Cổ Yêu bộ tộc.","detail":"Trong trận đối đầu Tán Ma nhập thể Vương Lâm, hư ảnh Tiên nhân thi triển Hoá Tiên Thuật khiến linh khí khắp Thiên Huyễn Tinh bị hút sạch và chuyển thành tiên lực. Thủ đoạn này buộc Tán Ma phải dùng Cổ Ma rút tinh hồn Thiên Huyễn Tinh để đối lại.","nguon":["@c0641"]},{"id":"co-ma-rut-ra-tinh-hon","name":"Cổ Ma rút ra tinh hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông Cổ Ma","phamCap":"Không rõ","hePhai":"Cổ Ma/Cổ Tộc","soHuu":["Tán Ma"],"blurb":"Thủ đoạn Tán Ma dùng khi nhập thể Vương Lâm, hóa ma trảo rút tinh hồn Thiên Huyễn Tinh. Đây là đối trọng trực tiếp với Hoá Tiên Thuật của hư ảnh Tiên nhân.","detail":"Tán Ma dùng ngôn ngữ Cổ Tộc gọi Cổ Ma rồi vươn ma trảo xuống Thiên Huyễn Tinh, rút tinh hồn của tinh cầu để so sức với việc hư ảnh Tiên nhân rút linh lực toàn tinh cầu thành tiên lực. Vương Lâm dù bị khống chế thân thể vẫn trực tiếp cảm nhận quá trình này và có cảm ngộ.","nguon":["@c0641"]},{"id":"quy-tac-kiem-thuc","name":"Quy tắc kiếm thức","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Một trong các thủ đoạn được Thiên Quỳ Tử liệt kê khi suy đoán địa vị của Vương Lâm trong Lôi Tiên Điện. Nó được nhắc cùng Lôi Thú, khôi lỗi và Ma.","detail":"Quy tắc kiếm thức không trực tiếp thi triển trong chương này, nhưng được Thiên Quỳ Tử xem là một phần hệ thống chiến lực khiến Vương Lâm trở nên đáng sợ và có khả năng là nhân vật trọng yếu của Lôi Tiên Điện.","nguon":["@c0641"]},{"id":"ngon-ngu-co-toc","name":"Ngôn ngữ Cổ Tộc","cn":"","loai":"khac","loaiLabel":"Ngôn ngữ thi triển thuật","phamCap":"Không rõ","hePhai":"Cổ Tộc","soHuu":["Tán Ma"],"blurb":"Ngôn ngữ được Tán Ma dùng khi phát động thủ đoạn Cổ Ma trong trận tại Thiên Huyễn Tinh. Nó gắn với lời gọi Cổ Ma và mệnh lệnh rút tinh hồn.","detail":"Khi đối đầu Hoá Tiên Thuật, Tán Ma không dùng lời thông thường mà dùng ngôn ngữ Cổ Tộc để gọi Cổ Ma và thi triển thủ đoạn rút tinh hồn Thiên Huyễn Tinh. Ngôn ngữ này cho thấy nguồn gốc cổ xưa của thần thông Tán Ma sử dụng.","nguon":["@c0641"]},{"id":"truu-hon","name":"Trừu hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bước thứ hai tu đạo","hePhai":"Cổ Ma / Tán Ma","soHuu":["Tán Ma"],"blurb":"Thần thông rút hồn quy mô lớn do Tán Ma thi triển khi khống chế thân thể Vương Lâm.","detail":"Trong chương này, Tán Ma dùng Trừu hồn rút tinh hồn Thiên Huyễn Tinh, quy mô vượt xa việc Tham Lang từng dùng Tiên sơn pháp bảo rút Sơn hồn ở Yêu Linh chi địa. Lực lượng tinh hồn tinh cầu được dùng để va chạm với tiên lực của Tiên nhân hư ảnh.","nguon":["@c0642"]},{"id":"vo-tuong-thien-ma-dao","name":"Vô Tướng Thiên Ma đạo","cn":"","loai":"than-thong","loaiLabel":"Ý cảnh thần thông","phamCap":"Truyền thừa Tiên nhân Huyễn gia","hePhai":"Huyễn gia","soHuu":["Tổ tiên Huyễn gia","Huyễn Vô Tình"],"blurb":"Đạo ý cảnh gốc do tổ tiên Huyễn gia cảm ngộ, là căn nguyên của Thiên Ma đạo và Vô Tướng đạo.","detail":"Huyễn Vô Tình muốn lấy ý cảnh của Liễu Mi để đạt tới Vô Tướng Thiên Ma đạo, xem đó là cơ hội liều mạng trước Tán Ma. Chương xác nhận Vạn Huyễn Thiên Ma đạo của Liễu Mi là lý do hắn thu nàng làm đệ tử để ngày sau cắn nuốt.","nguon":["@c0642"]},{"id":"thien-ma-dao","name":"Thiên Ma đạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông ý cảnh","phamCap":"Truyền thừa Tiên nhân Huyễn gia","hePhai":"Huyễn gia","soHuu":["Huyễn gia"],"blurb":"Một trong hai bộ thần thông ý cảnh do vị Tiên nhân Huyễn gia lưu lại.","detail":"Thiên Ma đạo cùng Vô Tướng đạo được tách ra từ cảm ngộ Vô Tướng Thiên Ma đạo. Chương cho biết môn này tu luyện quá khó, trong tộc Huyễn gia chưa ai chân chính luyện thành.","nguon":["@c0642"]},{"id":"vo-tuong-dao","name":"Vô Tướng đạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông ý cảnh","phamCap":"Truyền thừa Tiên nhân Huyễn gia","hePhai":"Huyễn gia","soHuu":["Huyễn gia"],"blurb":"Một trong hai bộ thần thông ý cảnh của truyền thừa Huyễn gia.","detail":"Vô Tướng đạo cùng Thiên Ma đạo vốn phân ra từ Vô Tướng Thiên Ma đạo do tổ tiên Huyễn gia cảm ngộ. Hai bộ đạo pháp này là nền tảng để Huyễn Vô Tình mưu cầu hợp nhất ý cảnh.","nguon":["@c0642"]},{"id":"thien-huyen-vo-tinh-dao","name":"Thiên Huyễn Vô Tình đạo","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Huyễn gia","soHuu":["Liễu Mi"],"blurb":"Thiên Huyễn Vô Tình đạo là đạo pháp Liễu Mi tu luyện. Công pháp này khiến nàng nhiều khi không phân rõ vô tình hay hữu tình mới là bản thân mình.","detail":"Trong chương 643, Thiên Huyễn Vô Tình đạo được nhắc như căn cơ tu luyện của Liễu Mi, liên quan trực tiếp tới ý cảnh bị Huyễn Vô Tình cắn nuốt để cưỡng ép sinh ra một tia Vô Tướng Thiên Ma.","nguon":["@c0643"]},{"id":"than-thong-loi-he","name":"Thần thông Lôi hệ","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Thần thông Lôi hệ được Vương Lâm dùng để trị oán khí trong thân thể Vương Bình. Lôi quang từ mi tâm hắn truyền qua tay, ép hắc khí trong người đứa trẻ ngưng tụ ra ngoài rồi bị bóp nát.","detail":"Trong đời sống ẩn cư tại thôn Lạc Nguyệt, Vương Lâm dùng thần thông Lôi hệ phối hợp với đan dược do Liễu Mi lưu lại để điều trị cho Vương Bình. Khi Vương Bình ngủ, lôi quang từ mi tâm Vương Lâm truyền vào thân thể đứa trẻ, khiến hắc khí bị ép ra khỏi mi tâm và tiêu tán, giúp sắc mặt Vương Bình dần có huyết sắc hơn.","nguon":["@c0644"]},{"id":"xua-tan-oan-khi","name":"Xua tan oán khí","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn Vương Lâm dùng trong đời sống phàm tục tại thôn Lạc Nguyệt để bảo hộ Vương Bình khỏi oán khí.","detail":"Trong mười năm sống như phàm nhân, Vương Lâm gần như không thi triển thần thông nào khác, chỉ ban đêm xua tan oán khí bên ngoài cho Vương Bình. Việc này cho thấy hắn vẫn âm thầm dùng năng lực tu sĩ để che chở con trong khi bản thân cố hòa vào đời thường.","nguon":["@c0645"]},{"id":"sinh-tu-luan-hoi","name":"Sinh tử luân hồi","cn":"","loai":"khac","loaiLabel":"Ý cảnh","phamCap":"Không rõ","hePhai":"Đạo tâm","soHuu":["Vương Lâm"],"blurb":"Cảm ngộ trọng yếu của Vương Lâm khi sống đời phụ tử cùng Vương Bình ở thôn Lạc Nguyệt.","detail":"Qua nhiều năm quan sát Vương Bình trưởng thành và sống giữa sinh lão bệnh tử của phàm nhân, Vương Lâm sinh ra cảm ngộ sâu hơn về sinh tử luân hồi. Cảm ngộ này khiến đạo tâm vốn mệt mỏi của hắn dần thoát khỏi trạng thái cũ và trở thành nền tảng cho biến hóa ý cảnh về sau.","nguon":["@c0645"]},{"id":"nhan-qua-tuan-hoan","name":"Nhân quả tuần hoàn","cn":"","loai":"khac","loaiLabel":"Ý cảnh","phamCap":"Không rõ","hePhai":"Đạo tâm","soHuu":["Vương Lâm"],"blurb":"Hướng thăng hoa ý cảnh được nêu khi Vương Lâm hoàn thiện cảm ngộ sinh tử.","detail":"Chương chỉ ra hoàn thiện sinh tử là nhân quả tuần hoàn. Vương Lâm đã có dấu hiệu thăng hoa ý cảnh theo hướng nhân quả, nhưng do lý giải về “sinh” còn thiếu nên sự biến hóa chưa hoàn toàn thành tựu.","nguon":["@c0645"]},{"id":"y-canh-thang-hoa","name":"Ý cảnh thăng hoa","cn":"","loai":"khac","loaiLabel":"Đạo tâm","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm","Liễu Mi"],"blurb":"Biến hóa hiếm gặp của ý cảnh tu sĩ, được dùng để lý giải cơ duyên của Liễu Mi và trạng thái hiện tại của Vương Lâm.","detail":"Ý cảnh của tu sĩ thường gần như cố định, nên việc thăng hoa ý cảnh là biến hóa hiếm và quan trọng. Liễu Mi từng vì có dấu hiệu này mà được Huyễn Gia Lão Tổ coi trọng, còn Vương Lâm trong đời sống phàm tục cũng xuất hiện dấu hiệu tương tự từ cảm ngộ sinh tử và nhân quả.","nguon":["@c0645"]},{"id":"khau-quyet-tu-dao-ton-thai-truyen-cho-vuong-binh","name":"Khẩu quyết tu đạo Tôn Thái truyền cho Vương Bình","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Khẩu quyết tu đạo","phamCap":"không rõ","hePhai":"Tôn Thái truyền lại","soHuu":["Vương Bình","Tôn Thái"],"blurb":"Khẩu quyết tu đạo do Tôn Thái âm thầm truyền cho Vương Bình trong thời gian nhận hắn làm cháu nuôi. Vương Bình biết khẩu quyết này nhưng nói chưa từng tu luyện.","detail":"Tôn Thái mượn danh nghĩa nhận Vương Bình làm cháu nuôi để âm thầm truyền pháp thuật và khẩu quyết tu đạo cho hắn. Vương Lâm biết việc này bằng thần thông của mình, nhưng vẫn kiên quyết cấm Vương Bình tiếp tục bước vào con đường tu đạo.","nguon":["@c0646"]},{"id":"hu-anh-bao-ho-sau-lung-vuong-binh","name":"Hư ảnh bảo hộ sau lưng Vương Bình","aliases":["Hư ảnh sau lưng Vương Bình"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông bảo hộ","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm","Vương Bình"],"blurb":"Thủ đoạn bảo hộ do Vương Lâm trao cho Vương Bình tại Vương Phủ. Hư ảnh dung nhập sau lưng Vương Bình, trở thành chỗ dựa để hắn hành sự trên Nhiễm Vân tinh.","detail":"Khi Vương Bình muốn tự mình trở thành chí tôn trong phàm nhân, Vương Lâm chấp thuận và vung tay để hư ảnh phía sau xuất hiện, dung nhập vào sau lưng con. Vương Lâm nói mang theo vật này thì ở Nhiễm Vân tinh, Vương Bình có thể làm được hết thảy.","nguon":["@c0650"]},{"id":"y-canh-tinh-yeu-khong-hoi-han","name":"Ý cảnh tình yêu không hối hận","cn":"","loai":"khac","loaiLabel":"Ý cảnh","phamCap":"không rõ","hePhai":"","soHuu":["Thanh Nghi"],"blurb":"Ý cảnh mà Thanh Nghi cảm ngộ khi ở bên Vương Bình, gắn với tình yêu không hối hận.","detail":"Hai mươi năm trước, Thanh Nghi ở bên Vương Bình mà cảm ngộ thiên đạo, đạt được ý cảnh lấy tình yêu không hối hận làm cốt lõi. Ý cảnh này đi cùng lựa chọn của nàng: xem tu vi như bụi bặm, không muốn làm thần tiên vô tình mà muốn làm người thường có tình.","nguon":["@c0654"]},{"id":"than-thuc-loi-dao-tu","name":"Thần thức Lôi Đạo Tử","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông / thần thức","phamCap":"Không rõ","hePhai":"Lôi hệ","soHuu":["Lôi Đạo Tử"],"blurb":"Thần thức mang lôi uy của Lôi Đạo Tử, từng bao trùm toàn bộ Nhiễm Vân tinh trong chớp mắt.","detail":"Khi Lôi Đạo Tử cưỡi lôi thú đến Nhiễm Vân tinh, thần thức này quét ngang toàn tinh, khiến tu sĩ chấn động tinh thần, yêu vật run rẩy và phàm nhân hôn mê. Sau đó hắn tập trung thần thức vào thôn nhỏ trong núi nơi Vương Bình ở, mở đầu biến cố trực tiếp với Vương Bình và Thanh Nghi.","nguon":["@c0655"]},{"id":"loi-quang-loi-dao-tu","name":"Lôi quang Lôi Đạo Tử","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Lôi pháp","phamCap":"Không rõ","hePhai":"Lôi hệ","soHuu":["Lôi Đạo Tử"],"blurb":"Lôi quang quanh thân Lôi Đạo Tử, dùng trong đối kháng và phá hủy.","detail":"Lôi Đạo Tử dùng lôi quang quanh thân để đỡ quyền của tiên vệ khôi lỗi. Sau đó hắn gom điện quang vào chân giẫm xuống, làm căn phòng nơi Vương Bình và Thanh Nghi ở tan biến, đồng thời tạo vòng lôi quang lan ra bốn phía.","nguon":["@c0655"]},{"id":"thien-dia-chi-loi-thu","name":"Thiên địa chi lôi, thu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi hệ","soHuu":["Lôi Đạo Tử"],"blurb":"Pháp quyết thu lôi Lôi Đạo Tử thi triển cùng thiết côn khắc phù để dẫn lôi lực của Vương Lâm.","detail":"Trong giao chiến tại bình nguyên phía tây Nhiễm Vân tinh, Lôi Đạo Tử cắm thiết côn xuống đất, bấm quyết và hô thu thiên địa chi lôi, muốn dùng pháp bảo thu nạp lôi cầu của Vương Lâm. Lôi lực quá mạnh khiến thiết côn rạn nứt rồi sụp đổ, pháp quyết không thể xoay chuyển thế trận.","nguon":["@c0656"]},{"id":"y-canh-loi-uy","name":"Ý cảnh lôi uy","cn":"","loai":"than-thong","loaiLabel":"Ý cảnh","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ý cảnh liên quan lôi uy nằm trong nguyên thần Vương Lâm. Ở chương này, nó được nhắc như một phần sức mạnh chưa phóng xuất khi Lôi Đạo Tử quan sát hắn.","detail":"Trong lúc Lôi Đạo Tử dò xét Vương Lâm, chương cho biết nguyên thần Vương Lâm còn có lôi uy chưa được phóng xuất. Tầng ý cảnh này góp phần làm nền cho năng lực lôi hệ vượt thường của hắn trong trận chiến.","nguon":["@c0657"]},{"id":"loi-chi-tien-thu","name":"Lôi chi tiên thú","cn":"","loai":"than-thong","loaiLabel":"Thần thông triệu hồi","phamCap":"Lôi Tiên Điện","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử"],"blurb":"Thần thông triệu hồi lôi thú của Lôi Đạo Tử. Lôi quang khắp trời ngưng tụ thành lôi cầu rồi hóa thành lôi thú bất phàm.","detail":"Lôi Đạo Tử chỉ trời thi triển Lôi chi tiên thú, khiến lôi quang trên không trung tụ lại thành lôi cầu rồi hóa thành lôi thú của Lôi Tiên Điện. Tiếng sấm từ thần thông này làm tu sĩ trên Nhiễm Vân tinh chấn động tâm thần và linh lực hỗn loạn.","nguon":["@c0657"]},{"id":"loi-tien-kiep","name":"Lôi tiên kiếp","cn":"","loai":"than-thong","loaiLabel":"Lôi hệ thần thông","phamCap":"Không rõ","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử"],"blurb":"Lôi hệ thần thông của Lôi Đạo Tử, ngưng tia chớp tím thành hàng rào điện quang. Chiêu này bị bảy phù văn lôi của Vương Lâm phá tan.","detail":"Lôi Đạo Tử dùng Lôi tiên kiếp trong trận đấu với Vương Lâm, đưa tử lôi trên tay thành điện quang lao tới. Bảy phù văn lôi do Vương Lâm vẽ bằng tiên bút phá vỡ tử lôi, khiến Lôi Đạo Tử phun máu lùi xa.","nguon":["@c0657"]},{"id":"bay-phu-van-loi-bang-tien-but","name":"Bảy phù văn lôi bằng tiên bút","cn":"","loai":"than-thong","loaiLabel":"Phù văn lôi pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông Vương Lâm thi triển bằng tiên bút màu vàng. Bảy bút họa dung nhập nguyên thần, hóa thành lôi quang trắng mang thiên lôi thái cổ.","detail":"Vương Lâm dùng tiên bút vẽ bảy phù văn, mỗi nét đều dung nhập một phần nguyên thần đã biến dị sau khi thôn phệ nửa Thái Cổ Lôi Long. Khi hoàn thành, phù văn từ kim quang hóa thành lôi quang trắng, phá tan Lôi tiên kiếp và làm Lôi Đạo Tử lần đầu thua trên phương diện lôi điện thần thông.","nguon":["@c0657"]},{"id":"thien-loi-thai-co-loi-uy-thai-co-loi-long","name":"Thiên lôi thái cổ / lôi uy Thái Cổ Lôi Long","cn":"","loai":"than-thong","loaiLabel":"Lôi uy","phamCap":"Thái cổ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Lôi uy bắt nguồn từ nguyên thần Vương Lâm sau khi thôn phệ nửa Thái Cổ Lôi Long. Nó khiến lôi hệ thần thông trên thế gian khó thương tổn được hắn.","detail":"Chương nhấn mạnh nguyên thần Vương Lâm đã biến dị vì từng thôn phệ nửa Thái Cổ Lôi Long, khiến phù văn lôi hắn vẽ mang khí tức thiên lôi thái cổ. Lôi uy này áp chế Lôi tiên kiếp của Lôi Đạo Tử và đặt Vương Lâm vào vị thế vượt trội trong lôi pháp.","nguon":["@c0657"]},{"id":"nguyen-luc-phap-thuat-buoc-thu-hai","name":"Nguyên lực pháp thuật bước thứ hai","cn":"","loai":"than-thong","loaiLabel":"Nguyên lực thần thông","phamCap":"Bước thứ hai","hePhai":"","soHuu":["Lôi Đạo Tử"],"blurb":"Pháp thuật dựa trên nguyên lực thiên địa của tu sĩ bước thứ hai. Lôi Đạo Tử dùng nó để uy hiếp Vương Lâm sau khi lôi hệ thần thông bị áp chế.","detail":"Sau khi bị bảy phù văn lôi đánh lui nhưng nhanh chóng khôi phục nhờ tiên lực và một tia nguyên lực thiên địa, Lôi Đạo Tử tuyên bố sẽ thi triển nguyên lực pháp thuật chỉ tu sĩ bước thứ hai mới tu luyện được. Vương Lâm không lùi mà muốn tự mình nếm thử nguyên lực thần thông của Âm Hư tu sĩ.","nguon":["@c0657"]},{"id":"than-thong-hai-mat","name":"Thần thông hai mắt","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử"],"blurb":"Thần thông Lôi Đạo Tử vận dụng ở hai mắt để nhìn thấu bí mật của mục tiêu.","detail":"Trong trận với Vương Lâm, Lôi Đạo Tử lần đầu thi triển thần thông này ở hai mắt để quan sát Vương Bình, qua đó nhận ra Vương Bình không phải phàm nhân mà là oán anh và phát hiện hai đạo kiếm khí đáng sợ trong thân thể đối phương.","nguon":["@c0658"]},{"id":"nguyen-luc-loi-dinh","name":"Nguyên lực lôi đỉnh","aliases":["Nguyên lực lôi đỉnh của Lôi Đạo Tử"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Nguyên lực thần thông bước thứ hai","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử"],"blurb":"Nguyên lực thần thông của Lôi Đạo Tử, biến thiên địa thành cự đỉnh màu lam để luyện hóa đối thủ.","detail":"Khi bị Trảm La quyết uy hiếp sinh tử, Lôi Đạo Tử điểm mi tâm, dẫn nguyên lực thiên địa từ thiên linh cái, khiến trời thành miệng đỉnh, đất thành thân đỉnh. Trong đại đỉnh, lôi điện mang thần thông và đạo niệm liên tục đánh xuống, buộc Vương Lâm, Tiên vệ khôi lỗi và lôi thú phải cùng phá đỉnh.","nguon":["@c0658"]},{"id":"dao-niem-than-loi","name":"Đạo niệm thần lôi","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử"],"blurb":"Lôi điện trong Nguyên lực lôi đỉnh, do ý niệm và đạo niệm của Lôi Đạo Tử biến thành.","detail":"Bên trong lôi đỉnh, từng đạo lôi điện không chỉ là thần thông mà còn chứa đạo niệm của Lôi Đạo Tử. Chúng liên tục oanh kích Vương Lâm, khiến thân hình hắn chấn động nhưng không đánh tan được nguyên thần biến dị của hắn như với tu sĩ Vấn Đỉnh thông thường.","nguon":["@c0658"]},{"id":"tram-la-quyet","name":"Trảm La quyết","aliases":["Trảm La"],"cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông kiếm quyết được Vương Lâm thi triển liên tiếp trong trận với Lôi Đạo Tử. Khi phối hợp lôi thú và Tiên vệ, nó trực tiếp góp phần phá vỡ đại đỉnh lôi hỏa.","detail":"Trong chương này, Vương Lâm nhớ lời Huyễn gia lão tổ từng nói về uy lực Trảm La khi đạt bước thứ hai, rồi dùng hai ngón tay làm kiếm thi triển Trảm La lần nữa. Do nguyên lực không đủ, việc thi triển liên tiếp khiến nguyên lực nguyên thần gần cạn và cảnh giới có dấu hiệu dao động, nhưng vẫn góp phần quyết định làm đại đỉnh sụp đổ.","nguon":["@c0659"]},{"id":"dao-phong-an-thu-ba-cua-loi-thu","name":"Đạo phong ấn thứ ba của lôi thú","cn":"","loai":"bi-thuat","loaiLabel":"Phong ấn linh thú","phamCap":"không rõ","hePhai":"Lôi hệ","soHuu":["Vương Lâm","Xạ Thần Xa"],"blurb":"Đạo phong ấn được Vương Lâm dùng máu vẽ phù văn để mở trên lôi thú. Sau khi mở, lôi thú phóng ra lôi điện màu đen và khí tức nghịch thiên.","detail":"Vương Lâm thu hồi đại kiếm, dùng máu tươi vẽ phù văn tang thương rồi ấn vào mi tâm lôi thú để mở đạo phong ấn thứ ba. Biến hóa này khiến lôi quang của lôi thú từ ngân sắc hóa thành màu đen, khí tức giống tổ tiên viễn cổ áp đảo lôi thú Lôi Tiên Điện.","nguon":["@c0659"]},{"id":"tien-y-phap-thuat-duy-tri-vuong-binh","name":"Tiên ý pháp thuật duy trì Vương Bình","cn":"","loai":"khac","loaiLabel":"Pháp thuật","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Pháp thuật duy trì quá trình tồn tại và trưởng thành của Vương Bình trong hơn bảy mươi năm. Nó khiến một tia hồn phách và kiếm khí có thể đi qua một đời phàm tục.","detail":"Chân tướng được hé lộ rằng Vương Bình không sinh trưởng như thân thể bình thường: thân thể do kiếm khí hóa thành, oan hồn được kiếm khí khác thủ hộ, còn hơn bảy mươi năm trưởng thành là do tiên ý pháp thuật của Vương Lâm duy trì.","nguon":["@c0659"]},{"id":"am-duong-hu-thuc-canh-gioi","name":"Âm Dương Hư Thực cảnh giới","cn":"","loai":"khac","loaiLabel":"Cảnh giới bước thứ hai","phamCap":"bước thứ hai","hePhai":"","soHuu":[],"blurb":"Cảnh giới bước thứ hai được Vương Lâm dùng để tự đánh giá giới hạn chiến lực sau khi tăng tiến tu vi và ý cảnh.","detail":"Vương Lâm nhận định tu sĩ Âm Hư có thể chiến thắng nhưng cực kỳ gian nan và hao nguyên lực, còn gặp Dương Thực thì không thể địch và chỉ có thể trốn. Đánh giá này khiến hắn đặt trọng tâm vào tiên ngọc và thiên địa nguyên lực.","nguon":["@c0660"]},{"id":"thien-dia-nguyen-luc","name":"Thiên địa nguyên lực","cn":"","loai":"khac","loaiLabel":"Nguồn lực tu sĩ bước thứ hai","phamCap":"bước thứ hai","hePhai":"","soHuu":["Vương Lâm","Lôi Đạo Tử"],"blurb":"Nguồn lực then chốt của tu sĩ bước thứ hai, được nhấn mạnh trong cuộc đối đầu giữa Vương Lâm và Lôi Đạo Tử.","detail":"Lôi Đạo Tử vì nguyên lực gần cạn nên không dám tùy tiện thi triển pháp thuật mạnh. Vương Lâm sau khi tự xét khoảng cách với tu sĩ Âm Dương Hư Thực cũng coi việc tăng thiên địa nguyên lực là chuyện trọng yếu.","nguon":["@c0660"]},{"id":"loi-mac","name":"Lôi mạc","cn":"","loai":"than-thong","loaiLabel":"Phòng ngự lôi pháp","phamCap":"","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử"],"blurb":"Màn lôi phòng ngự do Lôi Đạo Tử tạo ra để chống lại vòng vây của Vương Lâm.","detail":"Lôi Đạo Tử bóp nát ngọc giản lôi quang, hóa thành màn lôi bao quanh thân thể. Lôi mạc chống đỡ Thất Tinh kiếm trận, tiên vệ khôi lỗi, lôi thú và các chủ hồn trong Tôn Hồn Phiên trước khi hắn bị ép phải tản phòng ngự.","nguon":["@c0660"]},{"id":"ba-chung-cuc-chu-hon","name":"Ba chung cực chủ hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông Tôn Hồn Phiên","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ba chủ hồn cực mạnh do hồn phách trong Tôn Hồn Phiên dung hợp tạo thành.","detail":"Trong trận vây Lôi Đạo Tử, vô số hồn phách trong Tôn Hồn Phiên dung hợp thành kỳ lân hắc khí, người khổng lồ hắc khí và châm đen vô hình. Đây là thế công mạnh nhất mà Vương Lâm bày ra từ Tôn Hồn Phiên lúc này, phối hợp tiên vệ, lôi thú và kiếm trận công phá lôi mạc.","nguon":["@c0660"]},{"id":"than-thong-bao-menh-cua-loi-tien-dien-su-gia","name":"Thần thông bảo mệnh của Lôi Tiên Điện sứ giả","cn":"","loai":"than-thong","loaiLabel":"Thần thông bảo mệnh","phamCap":"","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử"],"blurb":"Thần thông bảo mệnh mà Lôi Đạo Tử dùng để uy hiếp khi bị vây ép.","detail":"Lôi Đạo Tử nói mỗi sứ giả Lôi Tiên Điện đều có thần thông bảo mệnh. Trong tình trạng nguyên lực thiếu hụt, nếu thi triển thì phải hi sinh thọ nguyên và có thể khiến tu vi tụt xuống, nên hắn không chắc có thể giết được Vương Lâm.","nguon":["@c0660"]},{"id":"cam-che-khong-che-nguyen-than","name":"Cấm chế khống chế nguyên thần","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Cấm chế do Vương Lâm dùng Cấm Phiên tạo ra để khống chế nguyên thần Lôi Đạo Tử.","detail":"Vương Lâm dùng Cấm Phiên phóng ra tổ hợp cấm chế như tinh quang, nhập vào mi tâm Lôi Đạo Tử, xuyên qua kinh mạch tới nguyên thần rồi hóa thành võng cấm chế bao vây. Lôi Đạo Tử ngoài mặt chịu khống chế nhưng tin rằng sau khi nguyên lực khôi phục sẽ phá được.","nguon":["@c0660"]},{"id":"luyen-che-tien-ve","name":"Luyện chế tiên vệ","cn":"","loai":"bi-thuat","loaiLabel":"Bí pháp luyện khôi lỗi","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Bí pháp Vương Lâm định dùng để biến Lôi Đạo Tử thành tiên vệ thứ hai.","detail":"Vương Lâm quyết định luyện Lôi Đạo Tử thành tiên vệ để triệt để yên tâm, vì đối phương phù hợp điều kiện luyện chế. Hắn còn tính đến việc kết hợp lôi thú bên ngoài nhằm tăng xác suất thành công.","nguon":["@c0660"]},{"id":"nguyen-than-khi","name":"Nguyên thần khí","cn":"","loai":"khac","loaiLabel":"Thuật pháp phụ trợ luyện chế","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Khí nguyên thần Vương Lâm phun ra để mở màn quá trình luyện hóa Lôi Đạo Tử.","detail":"Trong động phủ trên tinh cầu xám, Vương Lâm phun nguyên thần khí hóa thành vô số phù văn rơi lên người Lôi Đạo Tử. Đây là bước phụ trợ trước khi hắn dùng Côn Cực Tiên rút nguyên thần đối phương.","nguon":["@c0660"]},{"id":"cam-che-dien-quang","name":"Cấm chế điện quang","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Cấm chế Vương Lâm hạ sẵn trên nguyên thần Lôi Đạo Tử để khóa chặt đối phương khi phản kháng.","detail":"Khi Lôi Đạo Tử vừa muốn phản kháng, cấm chế trên nguyên thần lập tức bùng phát thành lưới điện quang, phối hợp tiên vệ khôi lỗi, lôi thú, chủ hồn và kiếm trận khiến nguyên thần hắn không thể thoát về thân thể.","nguon":["@c0661"]},{"id":"dinh-hoa-thien-dia","name":"Đỉnh Hóa Thiên Địa","aliases":["Nguyên lực lôi đỉnh","Đại đỉnh lôi hỏa của Lôi Đạo Tử"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Yêu cầu tu vi ít nhất Âm Hư","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử","Vương Lâm"],"blurb":"Thần thông lôi hệ ghi trong ngọc giản của Lôi Đạo Tử. Thuật này lấy đạo niệm bản thân ngưng hóa thành đỉnh, dung hợp ý thiên địa và nguyên lực bản thân.","detail":"Vương Lâm nhận ra đây là thuật Lôi Đạo Tử từng thi triển. Nội dung trong ngọc giản cho thấy người tu luyện phải có tu vi ít nhất Âm Hư mới có thể vận dụng, vì thuật liên quan đến đạo niệm, ý thiên địa và nguyên lực bản thân.","nguon":["@c0662"]},{"id":"loi-nguyen-thuat","name":"Lôi Nguyên Thuật","cn":"","loai":"cong-phap","loaiLabel":"Tiên thuật thiếu","phamCap":"Bản thiếu hạ phẩm tiên thuật","hePhai":"Lôi Tiên Điện","soHuu":["Vương Lâm"],"blurb":"Bản thiếu hạ phẩm tiên thuật dùng thiên lôi để hấp thu nguyên lực thiên địa vào cơ thể. Với nguyên thần lôi của Vương Lâm, thuật này có giá trị đặc biệt lớn.","detail":"Lôi Nguyên Thuật hấp thu nguyên lực thiên địa ẩn trong thiên lôi để tăng tốc ngưng tụ nguyên lực, giảm thời gian đình trệ ở cảnh giới Âm Dương Hư Thực. Tu sĩ bước đầu tiên thường khó chịu nổi thiên lôi nhập thể, nhưng Vương Lâm từng có lôi uy Thái Cổ trong nguyên thần nên cực kỳ coi trọng thuật này.","nguon":["@c0662","@c0686"]},{"id":"loi-uy-trong-ngoc-gian","name":"Lôi uy trong ngọc giản","cn":"","loai":"than-thong","loaiLabel":"Cấm chế lôi hệ","phamCap":"Có thể cản một số tu sĩ bước thứ hai","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Đạo Tử"],"blurb":"Lớp lôi quang ngăn thần thức trong ngọc giản khắc lôi thú. Nó mang một tia thiên địa lôi uy nhưng bị Vương Lâm phá bỏ nhờ lôi uy Thái Cổ trong nguyên thần.","detail":"Khi Vương Lâm dùng thần thức xem xét ngọc giản, lôi quang trong đó tạo thành trở ngại. Nhờ nguyên thần từng nuốt nửa Thái Cổ Thần Long và có lôi uy Thái Cổ, hắn phá được lớp cấm chế này để thấy hai thần thông bên trong.","nguon":["@c0662"]},{"id":"tu-dao-ba-buoc","name":"Tu đạo bước đầu tiên / bước thứ hai / bước thứ ba","cn":"","loai":"khac","loaiLabel":"Hệ thống tu đạo","phamCap":"không rõ","hePhai":"Tu đạo","soHuu":["Vương Lâm"],"blurb":"Hệ thống tu đạo được Vương Lâm suy ngẫm sau khi đạt Vấn Đỉnh hậu kỳ.","detail":"Vương Lâm nhìn lại bước đầu tiên của tu đạo, nhận ra bước thứ hai còn gian nan hơn, còn bước thứ ba thì hư vô mờ mịt đến mức những nhân vật như Thiên Vận Tử cũng chưa đạt tới.","nguon":["@c0664"]},{"id":"tu-dao-buoc-thu-tu","name":"Tu đạo bước thứ tư","cn":"","loai":"khac","loaiLabel":"Khái niệm tu đạo","phamCap":"không rõ","hePhai":"Tu đạo","soHuu":["Vương Lâm"],"blurb":"Câu hỏi về một cảnh giới hoặc tầng nhận thức vượt ngoài ba bước tu đạo.","detail":"Khi cưỡi lôi thú trong tinh không, Vương Lâm đặt vấn đề liệu sau ba bước tu đạo còn tồn tại bước thứ tư hay không. Chương nêu rõ không ai trong thế giới này có thể trả lời hắn.","nguon":["@c0664"]},{"id":"than-thong-loi-thu","name":"Thần thông lôi thú","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi hệ","soHuu":["Lôi thú"],"blurb":"Thần thông lôi hệ của lôi thú ngân sừng khi tiến vào Thiên Huyễn Tinh.","detail":"Lôi thú kéo lôi vân và lôi đình giáng xuống khi xuất hiện trên Thiên Huyễn Tinh, tạo lôi uy khiến nhiều tu sĩ chấn động và càng làm Vương Lâm giống sứ giả Lôi Tiên Điện.","nguon":["@c0664"]},{"id":"than-thong-chay-tron-cua-lao-gia-yeu-linh","name":"Thần thông chạy trốn của lão giả vùng đất Yêu Linh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"chưa rõ","hePhai":"chưa rõ","soHuu":["lão giả vùng đất Yêu Linh","Vương Lâm"],"blurb":"Thần thông đào tẩu của một lão giả từng khiến Vương Lâm chú ý ở vùng đất Yêu Linh.","detail":"Trên đường tới Vân Hà Tinh, Vương Lâm rút hồn phách lão giả trong Tôn Hồn Phiên để tra xét và ghi nhớ phương pháp chạy trốn này.","nguon":["@c0666"]},{"id":"hong-vu-thang-tien-qua","name":"Hồng vụ Thăng Tiên quả","cn":"","loai":"bi-thuat","loaiLabel":"Pháp thuật luyện hóa","phamCap":"chưa rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Cách Vương Lâm luyện Thăng Tiên quả thành hồng vụ để gây tê xúc tu Vọng Nguyệt.","detail":"Hắn nghiền Thăng Tiên quả thành chất lỏng rồi dùng nguyên thần khí đốt thành hồng vụ, khiến xúc tu hấp thu, chậm lại và tạm nới lỏng.","nguon":["@c0666"]},{"id":"lac-an-thang-tien-qua","name":"Lạc ấn Thăng Tiên quả","cn":"","loai":"bi-thuat","loaiLabel":"Phong ấn khống chế","phamCap":"chưa rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Ấn ký Vương Lâm đặt trong chất lỏng Thăng Tiên quả để ảnh hưởng gốc xúc tu Vọng Nguyệt.","detail":"Dựa vào tri thức Cổ Thần Đồ Ti về điểm hưng phấn của Vọng Nguyệt, Vương Lâm dung nhập chất lỏng có lạc ấn vào từng gốc xúc tu, dự định kích hoạt bằng tâm niệm.","nguon":["@c0666"]},{"id":"dai-than-thong-thuat-chua-ro","name":"Đại thần thông thuật chưa rõ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"chưa rõ","hePhai":"chưa rõ","soHuu":[],"blurb":"Dấu vết thần thông được Vương Lâm suy đoán từng xuất hiện trong thân thể Vọng Nguyệt.","detail":"Dao động tiên lực bất thường trong niêm dịch khiến Vương Lâm cho rằng có người từng vào bên trong Vọng Nguyệt và thi triển đại thần thông, dẫn tới biến hóa trạng thái của hung thú.","nguon":["@c0666"]},{"id":"dao-hoa-hoang-tuyen-de-tam-thuc","name":"Đạo hóa Hoàng Tuyền đệ tam thức","aliases":["Hoàng Tuyền lực","Hoàng Tuyền đệ tam thức"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"đạo hóa","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Đệ tam thức trong Đạo hóa Hoàng Tuyền, được Vương Lâm dùng dưới dạng Hoàng Tuyền lực để rút xương Vọng Nguyệt.","detail":"Khi thi triển, Hoàng Tuyền hóa thành hai luồng như hoàng long bám theo hai bên xương cốt, tạo lực hút và lực bóc kéo để rút cốt khỏi thân thể Vọng Nguyệt.","nguon":["@c0668"]},{"id":"rut-cot","name":"Rút cốt","cn":"","loai":"than-thong","loaiLabel":"Ứng dụng thần thông","phamCap":"chưa rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Ứng dụng Hoàng Tuyền lực nhằm bóc kéo xương cốt Vọng Nguyệt khỏi thân thể.","detail":"Vương Lâm áp hai tay vào hai đầu xương gãy, dùng Hoàng Tuyền lực làm dao róc dọc xương và quát lệnh rút cốt.","nguon":["@c0668"]},{"id":"tien-luc","name":"Tiên lực","cn":"","loai":"khac","loaiLabel":"Lực lượng tu vi","phamCap":"theo tu vi người dùng","hePhai":"tu sĩ","soHuu":["Vương Lâm"],"blurb":"Lực lượng tu vi được Vương Lâm vận chuyển đến cực hạn khi kéo xương sống Vọng Nguyệt.","detail":"Khi tiên lực toàn thân bùng phát, gân xanh và phù văn nổi lên trên hai tay Vương Lâm, giúp hắn từng chút kéo nửa đoạn xương sống khổng lồ ra khỏi thân thể Vọng Nguyệt.","nguon":["@c0669"]},{"id":"mo-phong-co-than-luyen-hoa-tien-ve","name":"Mô phỏng Cổ Thần luyện hóa Tiên Vệ","cn":"","loai":"luyen-the","loaiLabel":"Phương thức luyện hóa khôi lỗi","phamCap":"chưa rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm","Tiên Vệ"],"blurb":"Cách luyện hóa khiến Tiên Vệ có thân thể và lực lượng mạnh mẽ giống mô phỏng Cổ Thần.","detail":"Nhờ phương thức này, Tiên Vệ có lực lượng vượt xa Vương Lâm ở thời điểm hiện tại và đủ sức kéo nửa đoạn xương sống Vọng Nguyệt.","nguon":["@c0669"]},{"id":"tieng-noi-co-than","name":"Tiếng nói Cổ Thần","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Truyền thừa Cổ Thần","hePhai":"Cổ Thần","soHuu":["Vọng Nguyệt","Vương Lâm","Đồ Ti"],"blurb":"Âm thanh truyền thừa của Cổ Thần, được Vọng Nguyệt phát ra trong lúc truy sát và được Vương Lâm dùng để đáp lại. Việc Vọng Nguyệt biết loại tiếng nói này khiến Vương Lâm nghi hoặc về bản chất của nó.","detail":"Trong chương 670, Vọng Nguyệt phát ra âm thanh mà Vương Lâm nhận ra là tiếng nói Cổ Thần, điều không có trong ký ức Đồ Ti về Vọng Nguyệt. Khi bầu trời nứt vỡ vì thần thông phá nát, Vương Lâm xoay người phát ra tiếng nói Cổ Thần truyền thừa từ Đồ Ti, khiến khe nứt và thế sụp đổ tạm ngừng.","nguon":["@c0670"]},{"id":"ky-thuat-pha-nat-cua-bat-tinh-co-than","name":"Kỹ thuật phá nát của Bát Tinh Cổ Thần","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bát Tinh Cổ Thần","hePhai":"Cổ Thần","soHuu":["Vọng Nguyệt"],"blurb":"Thần thông phá nát mà Vương Lâm nhận ra là năng lực chỉ Bát Tinh Cổ Thần mới thi triển được. Trong chương này, nó khiến bầu trời bốn phía nứt vỡ, đẩy Vương Lâm vào nguy cơ sinh tử.","detail":"Tiếng nói Cổ Thần của Vọng Nguyệt làm bầu trời quanh Vương Lâm xuất hiện vô số khe nứt như sắp sụp đổ. Vương Lâm nhận ra đây là kỹ thuật phá nát của Bát Tinh Cổ Thần, một loại thần thông có thể khiến vật bị nhìn thấy tan vỡ thành tro bụi.","nguon":["@c0670"]},{"id":"ngon-xuat-phap-tuy","name":"Ngôn xuất pháp tùy","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Hiệu ứng lời nói hóa thành uy lực, được dùng để mô tả tiếng quát của Vương Lâm khi gọi Thất Tinh Kiếm Trận trở về. Âm thanh hóa thành nhiều tia sấm sét phóng vào kiếm trận.","detail":"Khi Vương Lâm gầm gọi Thất Tinh Kiếm Trận trong khe nứt của Vọng Nguyệt, giọng quát của hắn được ví như ngôn xuất pháp tùy. Lời nói hóa thành nhiều sấm sét, dẫn động kiếm trận trở lại để hắn ra lệnh tự bạo.","nguon":["@c0670"]},{"id":"dinh-than-thuat","name":"Định Thân Thuật","cn":"","aliases":["Định thân thuật","Định"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Thần thông định thân được Vương Lâm dùng khi tiên lực bùng phát nhờ tiên tửu.","detail":"Trong lúc bị Vọng Nguyệt truy sát, Vương Lâm uống hai giọt tiên tửu còn lại rồi thi triển Định Thân Thuật, khiến trời đất như ngừng vận chuyển trong chốc lát. Thuật này tạm khóa đàn Vọng Nguyệt nhỏ và sau đó khóa Tham Lang, nhưng không ảnh hưởng tới bản thể Vọng Nguyệt khổng lồ.","nguon":["@c0672"]},{"id":"than-thong-doi-vi-tri-cua-cu-dinh","name":"Thần thông đổi vị trí của cự đỉnh","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông pháp bảo","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Tham Lang"],"blurb":"Thần thông do Tham Lang kích phát thông qua Cự Đỉnh để đổi vị trí với mục tiêu khác.","detail":"Tham Lang phun máu lên Cự Đỉnh để kích hoạt sóng tròn, đổi vị trí với một Vọng Nguyệt nhỏ đang lao nhanh nhất. Hắn định tiếp tục đổi chỗ với Vương Lâm nhưng bị Định Thân Thuật chặn lại.","nguon":["@c0672"]},{"id":"co-than-chi","name":"Cổ Thần Chỉ","cn":"","aliases":["Một chỉ Cổ Thần","Một chỉ của Cổ Thần do Vọng Nguyệt huyễn hóa"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Uy năng Cổ Thần","hePhai":"Cổ Thần","soHuu":["Vọng Nguyệt"],"blurb":"Uy năng một chỉ được Vọng Nguyệt huyễn hóa khi rơi vào trạng thái phẫn nộ.","detail":"Khi ký hiệu ngôn ngữ Cổ Thần lóe lên trong mắt Vọng Nguyệt, một ngón tay hư ảo trăm trượng xuất hiện. Một chỉ này phá vỡ bình phong Sơn Hà Đồ và khiến Tham Lang phun máu nguyên thần, cho thấy uy áp vượt xa đạo niệm tu sĩ thông thường.","nguon":["@c0672"]},{"id":"son-ha-do","name":"Sơn Hà Đồ","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Bình phong Sơn Hà Đồ","Vương Lâm"],"blurb":"Thần thông hiện trên bình phong trong tinh không. Vương Lâm nhận ra nó và mạo hiểm đoạt lấy giữa lúc Cổ Thần Chỉ truy đuổi Tham Lang.","detail":"Sơn Hà Đồ là thần thông gắn với bình phong trôi trong tinh không nơi Vọng Nguyệt thức tỉnh. Vương Lâm lợi dụng thời điểm Cổ Thần Chỉ chuyển hướng về Tham Lang, ôm bình phong thu vào túi trữ vật rồi rút lui.","nguon":["@c0673"]},{"id":"sinh-menh-lac-an","name":"Sinh Mệnh Lạc Ấn","cn":"","aliases":["Sinh Chi Lạc Ấn"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm","Tiên Vệ"],"blurb":"Ấn pháp phòng ngự được tạo từ hàng trăm vạn đạo sát lục khí trong Tiên Vệ. Nó bị Cổ Thần Chỉ nghiền nát như giấy mỏng.","detail":"Khi Cổ Thần Chỉ ép tới, Vương Lâm rút chuẩn bị trong Tiên Vệ, khiến hàng trăm vạn sát lục khí ngưng thành Sinh Mệnh Lạc Ấn để cản một chỉ. Lạc ấn nhanh chóng vỡ vụn, không thể ngăn uy lực của ngón tay Cổ Thần.","nguon":["@c0673"]},{"id":"thai-co-loi-long-nguyen-than","name":"Thái cổ Lôi Long nguyên thần","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Hình thái nguyên thần","phamCap":"không rõ","hePhai":"Lôi","soHuu":["Vương Lâm"],"blurb":"Hình thái nguyên thần của Vương Lâm sau khi lớp màng giam nguyên thần bị Cổ Thần Chỉ phá vỡ. Nguyên thần hóa thành thái cổ Lôi Long, tạo lôi cầu cản địch và bỏ chạy.","detail":"Một chỉ Cổ Thần phá hủy nhục thân Vương Lâm đồng thời phá lớp màng bao quanh nguyên thần, khiến nguyên thần bùng ra hóa thái cổ Lôi Long. Hình thái này gầm rống, tạo nhiều lôi cầu đánh về Cổ Thần Chỉ rồi cuốn đồ vật và đồng bạn đào thoát.","nguon":["@c0673"]},{"id":"nguyen-than-chi-loi","name":"Nguyên thần chi lôi","cn":"","aliases":[],"loai":"khac","loaiLabel":"Năng lực lôi hệ","phamCap":"","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Năng lực lôi hệ gắn với nguyên thần dị hóa thái cổ Lôi Long của Vương Lâm. Lôi quang tự nhiên trên tinh cầu lôi điện có đặc tính gần giống loại lôi này.","detail":"Khi tiến vào tiểu tinh cầu lôi quang, Vương Lâm nhận ra lôi điện nơi đây không phải do pháp thuật hay thần thông biến hóa mà là lôi tự nhiên do trời đất sinh ra. Đặc tính của nó rất giống nguyên thần chi lôi của hắn, đồng thời giải thích vì sao con rối Tiên Vệ tỏ ra e dè trước lôi quang nơi này.","nguon":["@c0674"]},{"id":"loi-tien-thien-loi-hau-thien","name":"Lôi tiên thiên / lôi hậu thiên","cn":"","aliases":["Lôi tiên thiên","Lôi hậu thiên"],"loai":"khac","loaiLabel":"Phân loại lôi lực","phamCap":"","hePhai":"Lôi hệ","soHuu":[],"blurb":"Cách phân biệt lôi lực theo nguồn gốc: lôi hậu thiên do thần thông biến hóa, còn lôi tiên thiên do trời đất tự sinh. Lôi quang trên tinh cầu lôi điện thuộc loại tiên thiên.","detail":"Vương Lâm quan sát phản ứng do dự hiếm thấy của Tiên Vệ trước lôi quang và nhận định lôi ở nơi này là tự nhiên, không phải do pháp thuật thần thông huyễn hóa. Hắn phân biệt lôi hậu thiên là lôi do thần thông tạo thành, còn lôi tiên thiên là lôi do trời đất sinh ra; loại lôi tiên thiên này gần với nguyên thần chi lôi của hắn và thích hợp để hắn chữa thương, ngưng luyện nguyên thần cùng thân thể.","nguon":["@c0674"]},{"id":"than-thong-rut-linh-hon-linh-vat","name":"Thần thông rút linh hồn linh vật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Liên quan cảnh giới Đệ Nhị Bộ","hePhai":"Không rõ","soHuu":["Tán Ma","Vương Lâm"],"blurb":"Thần thông rút linh hồn của tinh cầu, núi, sông và linh vật tương tự. Vương Lâm nhờ cảm ngộ từ Tán Ma và núi đá tiên giới mà thử chạm tới phương pháp này.","detail":"Chương này nêu rõ loại thần thông rút hồn linh vật là điều tu sĩ Đệ Nhị Bộ mới hiểu rõ. Vương Lâm từng có cảm ngộ khi Tán Ma rút Thiên Huyễn Tinh Hồn, nay dùng núi đá tiên giới của Tham Lang để thử kéo Sơn Hồn ra, nhưng khi mở rộng sang mặt đất thì bị phản lực chấn thương nhẹ.","nguon":["@c0675"]},{"id":"son-hon","name":"Sơn Hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Liên quan núi đá tiên giới","soHuu":["Vương Lâm","Tham Lang"],"blurb":"Linh hồn của núi đá tiên giới bị Vương Lâm rút ra thành quả cầu hư ảo. Bản này yếu hơn Sơn Hồn Tham Lang từng dùng nhưng vẫn tỏa khí tức cường đại.","detail":"Khi kiểm tra núi đá tiên giới bị hư hại, Vương Lâm dùng cảm ngộ rút hồn kéo ra một quả cầu hư ảo như sương mù. Quả cầu chứa tiên khí tổ hợp mạnh nhưng không ổn định vì bản thể núi đá đã bị tổn hại.","nguon":["@c0675"]},{"id":"than-thong-son-ha","name":"Thần thông Sơn Hà","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Sơn Hà Đồ","soHuu":["Tham Lang","Vương Lâm"],"blurb":"Thần thông do Sơn Hà Đồ hóa thành, gắn với hình tượng sơn hà trong pháp bảo. Chương này nhấn mạnh uy lực thật sự của Sơn Hà Đồ còn nằm ở nét bút vẽ bằng máu.","detail":"Khi Vương Lâm xem xét bình phong Sơn Hà Đồ, thần thông Sơn Hà được nhắc như năng lực pháp bảo có thể thi triển. Tuy vậy, điểm lợi hại chân chính của Sơn Hà Thiên Đạo Đồ không chỉ là hóa thành Sơn Hà, mà là truyền thuyết nét vẽ bằng máu của Thiên Đạo.","nguon":["@c0675"]},{"id":"phu-van-thien-nghich-vien-man","name":"Phù văn Thiên Nghịch viên mãn","cn":"","loai":"bi-thuat","loaiLabel":"Phù văn","phamCap":"Không rõ","hePhai":"Thiên Nghịch Châu","soHuu":["Vương Lâm"],"blurb":"Phù văn cổ xưa xuất hiện sau khi ngũ hành của Thiên Nghịch Châu viên mãn. Nó tỏa khí tức tang thương cực mạnh trong tâm thần và trước người Vương Lâm.","detail":"Sau khi thuộc tính kim của Thiên Nghịch đạt viên mãn, Vương Lâm nhỏ máu dung hợp thần thức lạc ấn lên hạt châu. Tâm thần hắn chấn động, phù văn tang thương hiện ra rồi được hắn vẽ trước người, khí tức cổ xưa vượt xa lần Tán Ma rút Thiên Huyễn Tinh Hồn.","nguon":["@c0675"]},{"id":"cam-che-tu-quang","name":"Cấm chế tử quang","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Thiên Nghịch dị biến","soHuu":[],"blurb":"Cấm chế hình thành trong vùng tử quang sau khi Hạt Châu Thiên Nghịch viên mãn. Nó bao phủ khu vực quanh cánh cửa tím và ngăn sinh linh tiến vào.","detail":"Khi tử quang lan rộng trên tinh cầu lôi quang và tầng đá ngoài, một tầng cấm chế cực mạnh hình thành trong phạm vi bao phủ. Vương Lâm chỉ nhìn đã bị chấn nhiếp; dưới cấm chế này, sinh linh không thể tiến vào khu vực đang bị tử quang cắt biệt.","nguon":["@c0676"]},{"id":"than-thong-cat-dut-khu-vuc-tu-quang","name":"Thần thông cắt đứt khu vực tử quang","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thiên Nghịch dị biến","soHuu":[],"blurb":"Sức mạnh dị thường khiến vùng tử quang như bị đào khỏi La Thiên Tinh Vực. Khu vực quanh tinh cầu lôi quang bị tách biệt khỏi ngoại giới.","detail":"Trong phạm vi tử quang, không gian tạo cảm giác bị một loại thần thông đào ra và cắt đứt khỏi mọi thứ xung quanh. Hiện tượng này đi kèm sự tan rã của đất đá, tầng bao ngoài và cấm chế mạnh ngăn sinh linh tiếp cận.","nguon":["@c0676"]},{"id":"loi-an","name":"Lôi ấn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Thủ ấn Lôi hệ do Vương Lâm thi triển khi vận chuyển Lôi Nguyên Thuật trong Lôi Trì.","detail":"Một lần bắt quyết của Vương Lâm thực chất gồm chín thủ ấn được thi triển cực nhanh, tạo thành hiệu quả giống Lôi ấn để dẫn động Lôi Đình nhập thể và hỗ trợ chuyển hóa nguyên lực.","nguon":["@c0678"]},{"id":"cam-che-ky-di-cua-thien-nghich","name":"Cấm chế kỳ dị của Thiên Nghịch","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Thiên Nghịch","soHuu":["Vương Lâm"],"blurb":"Cấm chế kỳ dị liên quan tới Thiên Nghịch, tái hiện khi hạt châu hấp thu lôi điện trong Lôi Trì.","detail":"Sau khi Thiên Nghịch hút lôi điện, tử quang bên trong hạt châu lóe lên rồi tản ra, kéo theo cấm chế kỳ dị và cánh cửa lớn từng xuất hiện trước đó giữa trời đất.","nguon":["@c0678"]},{"id":"dao-sinh-tu-luan-hoi","name":"Đạo sinh tử luân hồi","cn":"","aliases":[],"loai":"khac","loaiLabel":"Đạo cảnh / cảm ngộ","phamCap":"Không rõ","hePhai":"Đạo sinh tử","soHuu":["Vương Lâm"],"blurb":"Cảm ngộ Đạo của Vương Lâm qua vòng chuyển sinh tử, tử sinh trong không gian Thiên Nghịch.","detail":"Vương Lâm quan sát vô số vật sáng biến hóa qua sinh tử, từ sinh đến tử rồi từ tử tới sinh, qua đó nhận ra đạo sinh tử luân hồi của chính mình. Cảm ngộ này không trực tiếp tăng tu vi nhưng làm tâm cảnh của hắn thăng hoa ở tầng Đạo.","nguon":["@c0680"]},{"id":"dao-nhan-qua","name":"Đạo nhân quả","cn":"","aliases":[],"loai":"khac","loaiLabel":"Đạo cảnh / cảm ngộ","phamCap":"Không rõ","hePhai":"Nhân quả","soHuu":["Vương Lâm"],"blurb":"Cảm ngộ nhân quả của Vương Lâm qua hình ảnh Lý Mộ Uyển, Vương Bình và Thanh Nghi.","detail":"Từ hình ảnh Lý Mộ Uyển tìm kiếm đáp án, cùng Vương Bình và Thanh Nghi sống cuộc đời bình thường, Vương Lâm hiểu thêm về vòng tuần hoàn nhân quả. Đây là một phần cơ duyên hiểu Đạo hắn đạt được trong Thiên Nghịch.","nguon":["@c0680"]},{"id":"buoc-thu-ba","name":"Bước thứ ba","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cảnh giới / đạo cảnh","phamCap":"Cực cao","hePhai":"Đạo cảnh","soHuu":["Vương Lâm"],"blurb":"Tầng cảnh giới thần bí mà Vương Lâm chưa đạt tới nhưng đã quan sát được khí tức sau cơ duyên Thiên Nghịch.","detail":"Sau khi trải qua cảnh giới trước cánh cửa thiên địa, Vương Lâm tự ví mình vẫn nhỏ bé như con kiến, nhưng đã trở thành con kiến có thể quan sát được bước thứ ba. Ánh mắt hắn sau cảm ngộ còn lưu khí tức này, đủ khiến một tu sĩ Dương Thực chấn động gần như sụp đổ.","nguon":["@c0680"]},{"id":"dao-yem","name":"Đạo Yểm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Truyền thuyết La Thiên","hePhai":"không rõ","soHuu":["Người thi triển Đạo Yểm trong truyền thuyết"],"blurb":"Đạo Yểm là thần thông trong truyền thuyết La Thiên Tinh Vực, từng khiến nhiều tu sĩ bước thứ hai không kịp tế pháp bảo đã bại. Thân Công Hổ nhận lầm dư uy ánh mắt tầm đạo của Vương Lâm là thuật này.","detail":"Theo ký ức và nhận định của Thân Công Hổ, Đạo Yểm từng xuất hiện vô số năm trước tại La Thiên Tinh Vực và đủ sức đánh bại tu sĩ bước thứ hai. Khi bị ánh mắt của Vương Lâm áp chế đến mất khả năng phản kháng, hắn cho rằng cảnh tượng ấy chính là Đạo Yểm trong truyền thuyết.","nguon":["@c0681"]},{"id":"canh-mong-tam-dao-tu-thien-nghich","name":"Cảnh mộng tầm đạo từ Thiên Nghịch","cn":"","loai":"khac","loaiLabel":"Cơ duyên cảm ngộ","phamCap":"Cơ duyên bước thứ ba","hePhai":"Thiên Nghịch","soHuu":["Vương Lâm"],"blurb":"Cảnh mộng tầm đạo từ Thiên Nghịch là cơ duyên khiến Vương Lâm nhìn thấy con đường dẫn tới bước thứ ba Tu Đạo. Chỉ một khe hở của Thiên Nghịch đã làm tâm tính, linh hồn và ý cảnh của hắn biến hóa sâu sắc.","detail":"Sau khi tỉnh lại, Vương Lâm nhận ra cảnh tượng chân thật như mộng do Thiên Nghịch mở ra đã hé cho hắn cánh cửa bước thứ ba. Trải nghiệm này khiến hắn hiểu uy năng Thiên Nghịch vượt xa tưởng tượng, đồng thời ý cảnh có dấu hiệu tiến gần Vấn Đỉnh đại viên mãn.","nguon":["@c0681"]},{"id":"bi-phap-loi-tien-dien-mo-duong-vao-loi-tien-gioi","name":"Bí pháp Lôi Tiên Điện mở đường vào Lôi Tiên Giới","cn":"","loai":"bi-thuat","loaiLabel":"Bí pháp","phamCap":"Bí pháp thế lực","hePhai":"Lôi Tiên Điện","soHuu":["Lôi Tiên Điện"],"blurb":"Bí pháp này cho phép một số tu sĩ bước thứ hai tiến vào Lôi Tiên Giới dù giới hạn thông thường là Vấn Đỉnh hậu kỳ đại viên mãn. Điều kiện được Thân Công Hổ nêu là tu vi chưa vượt quá Khuy Niết sơ kỳ.","detail":"Thân Công Hổ giải thích rằng Lôi Tiên Giới ở La Thiên có hạn chế tu vi khi mở ra, nhưng Lôi Tiên Điện nắm bí pháp đặc thù để đưa một số tu sĩ bước thứ hai vào trong. Bí pháp này chỉ áp dụng cho người chưa vượt qua Khuy Niết sơ kỳ.","nguon":["@c0681"]},{"id":"loi-than-thong-thuc-su","name":"Lôi thần thông thực sự","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Biểu hiện của Vương Lâm khi bước trên lôi đình trong Lôi Trì, được Thân Công Hổ xem là lôi thần thông chân chính.","detail":"Không phải tiên thuật công kích trực tiếp mà là trạng thái cảm ngộ và điều khiển bước chân theo quy luật lôi quang trong Lôi Trì. Thân Công Hổ coi cảnh tượng này là thứ hắn chờ đợi suốt hai năm để được chứng kiến.","nguon":["@c0683"]},{"id":"quy-luat-cua-sam-set","name":"Quy luật của sấm sét","cn":"","loai":"khac","loaiLabel":"Cảm ngộ quy luật","phamCap":"liên hệ bước thứ ba","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Tầng cảm ngộ về bản chất vận hành của sấm sét mà Vương Lâm chạm tới trong Lôi Trì.","detail":"Vương Lâm nhìn Lôi Trì đến mức quên thân thể và ngoại giới, chỉ còn lôi đình cùng các tia sáng ẩn hiện. Từ đó hắn bước đúng theo lôi quang, rồi nhận ra hiểu biết mới về sấm sét có liên hệ tới bước thứ ba và đặc biệt quan trọng cho con đường tu đạo của mình.","nguon":["@c0683"]},{"id":"loi-uy-nguyen-than","name":"Lôi uy nguyên thần","cn":"","loai":"khac","loaiLabel":"Năng lực nguyên thần","phamCap":"không rõ","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Lôi uy phát ra từ nguyên thần Vương Lâm do từng nuốt một nửa Thái Cổ Lôi Long.","detail":"Năng lực này khiến thân thể, nguyên thần và sấm sét của Vương Lâm gần như hòa hợp, nhưng khi đối diện Lôi Trì thì lôi uy ấy vẫn quá yếu so với uy thế sấm sét nơi đây, không đủ để cưỡng ép tiến sâu.","nguon":["@c0683"]},{"id":"tho-nap-loi-dinh","name":"Thổ nạp lôi đình","cn":"","loai":"cong-phap","loaiLabel":"Tu luyện","phamCap":"Không rõ","hePhai":"Lôi","soHuu":["Vương Lâm"],"blurb":"Cách Vương Lâm hấp thu lôi đình trong vòng trong Lôi Trì để tu luyện.","detail":"Vương Lâm khoanh chân thổ nạp trong vòng trong Lôi Trì, nơi lôi đình dày đặc và ẩn chứa thiên địa nguyên lực rất mạnh. Mỗi đạo lôi đình nhập thể đều khiến thân thể chấn động, toàn thân tê liệt và nguyên thần vận chuyển chậm chạp.","nguon":["@c0684"]},{"id":"nguyen-luc-than-thong-cua-chien-khong-liet","name":"Nguyên lực thần thông của Chiến Không Liệt","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi","soHuu":["Chiến Không Liệt"],"blurb":"Thần thông lôi quang màu tím của Chiến Không Liệt, phối hợp với kiếm gỗ màu tím.","detail":"Chiến Không Liệt bấm quyết tạo lôi quang màu tím, đồng thời dùng kiếm khí từ kiếm gỗ màu tím. Uy phong của chiêu thức có ẩn chứa thiên địa nguyên khí, được hắn triển khai khi chuẩn bị giao chiến với Thân Công Hổ.","nguon":["@c0684"]},{"id":"dan-dong-thien-loi-cua-than-cong-ho","name":"Dẫn động Thiên Lôi của Thân Công Hổ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi","soHuu":["Thân Công Hổ"],"blurb":"Lôi pháp Thân Công Hổ dùng khi chuẩn bị giao chiến với Chiến Không Liệt.","detail":"Thân Công Hổ giơ tay chỉ lên không trung như dẫn động thiên lôi, đồng thời Lôi Thú bên cạnh ngưng tụ sấm sét để phối hợp. Chiêu thức được triển khai trong thế đối đầu trực diện tại Lôi Trì.","nguon":["@c0684"]},{"id":"dan-loi-thuat","name":"Dẫn lôi thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông lôi hệ nguyên lực","hePhai":"Lôi Tiên Điện / Thân Công Hổ","soHuu":["Thân Công Hổ"],"blurb":"Thần thông lôi hệ của Thân Công Hổ, dùng nguyên lực bản thân dẫn sấm sét trời đất giáng xuống. Vương Lâm nhận xét thuật này có lôi uy nhưng thiếu lôi hồn và sức mạnh căn nguyên của sấm sét.","detail":"Trong trận đấu với Chiến Không Liệt tại Lôi Trì, Thân Công Hổ thi triển Dẫn lôi thuật, dẫn lôi quang từ hư không như thần long giáng xuống. Sau khi quan sát, Vương Lâm chỉ ra điểm thiếu của thuật này nằm ở căn nguyên: tuy có uy thế sấm sét nhưng chưa có lôi hồn, chưa chạm được sức mạnh thật của sấm sét.","nguon":["@c0685"]},{"id":"nguyen-luc-hoa-dinh","name":"Nguyên lực hóa đỉnh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông nguyên lực","hePhai":"","soHuu":[],"blurb":"Dạng thần thông nguyên lực được Vương Lâm dùng làm mốc so sánh khi đánh giá Dẫn lôi thuật của Thân Công Hổ.","detail":"Vương Lâm nhận định Dẫn lôi thuật của Thân Công Hổ tuy không phải nguyên lực hóa đỉnh nhưng uy lực lớn, qua đó cho thấy đây là một kiểu vận dụng nguyên lực đáng dùng làm chuẩn so sánh với thần thông lôi hệ.","nguon":["@c0685"]},{"id":"kiem-khi-cua-chien-khong-liet","name":"Kiếm khí của Chiến Không Liệt","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Thần thông kiếm đạo","hePhai":"Chiến gia","soHuu":["Chiến Không Liệt"],"blurb":"Thần thông kiếm đạo Chiến Không Liệt dùng khi giao thủ với Thân Công Hổ trong Lôi Trì.","detail":"Chiến Không Liệt phun nguyên khí lên kiếm gỗ, khiến kiếm tản ra kiếm khí nồng đậm, bay lên đối kháng lôi quang do Thân Công Hổ dẫn xuống. Va chạm giữa kiếm khí và lôi quang tạo tiếng nổ lớn, khiến đôi bên đều bị chấn lui.","nguon":["@c0685"]},{"id":"dan-dat-khi-tuc","name":"Dẫn dắt khí tức","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không nêu rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Hiện tượng khí tức của Vương Lâm tự nhiên áp chế Trương Tân Hải, khiến đối phương sinh phản ứng như phàm nhân đứng trước tu sĩ.","detail":"Tại Hoành Vân Sơn Phong, chỉ khí tức tỏa ra từ Vương Lâm đã khiến Trương Tân Hải theo bản năng cúi thấp, qua đó biểu hiện chênh lệch tầng cấp rất lớn giữa hai người.","nguon":["@c0687"]},{"id":"linh-quyet-tang-tho","name":"Linh quyết tăng thọ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không nêu rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông dùng linh quyết thiêu đốt linh lực của người nhận để kéo dài thọ nguyên thêm một thời hạn nhất định.","detail":"Vương Lâm đánh một đạo linh quyết vào giữa lông mày Trương Tân Hải, không trực tiếp thay đổi vận mệnh nhưng dùng linh lực của Trương Tân Hải thiêu đốt để tăng thêm mười năm tuổi thọ. Khi thi triển, Vương Lâm nhớ tới Lý Mộ Uyển và tiếc nuối năm xưa không thể dùng cách tương tự cho nàng.","nguon":["@c0687"]},{"id":"truyen-than-niem-toan-tinh-cau","name":"Truyền thần niệm toàn tinh cầu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không nêu rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông dùng thần niệm vang khắp toàn bộ Thanh Linh Tinh để truyền đạt ý chí của người thi triển.","detail":"Vương Lâm dùng thần niệm khiến tất cả tu sĩ trên Thanh Linh Tinh nghe được tuyên bố rằng tinh cầu này từ nay là tu chân tinh của hắn, đồng thời cấm mọi người bước vào Hoành Vân Sơn Phong.","nguon":["@c0687"]},{"id":"nhan-qua-y-canh","name":"Nhân quả ý cảnh","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Ý cảnh","phamCap":"Chưa rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ý cảnh của Vương Lâm đang chuyển từ đạo sinh tử luân hồi sang đạo nhân quả. Ở chương này, hắn dùng Côn Cực Tiên làm vật đại diện để bù cho việc ý cảnh chưa thể thực chất hóa hoàn toàn.","detail":"Vương Lâm nhận ra bản thể là nhân, nguyên thần là quả, từ đó nhìn thấy phương hướng của nhân quả ý cảnh. Ý cảnh này chưa thể ngưng hóa ra hình thái hư ảo như sinh tử luân hồi, nhưng đã đủ để hắn tế luyện Côn Cực Tiên, dùng pháp bảo này tạo vòng tròn nhân quả và áp chế viễn cổ kiếm ý của Hứa Lập Quốc.","nguon":["@c0688"]},{"id":"vien-co-kiem-y","name":"Viễn cổ kiếm ý","cn":"","aliases":[],"loai":"kiem-quyet","loaiLabel":"Kiếm ý","phamCap":"Chưa rõ","hePhai":"","soHuu":["Hứa Lập Quốc"],"blurb":"Kiếm ý tang thương mà Hứa Lập Quốc dung vào hình thái đại kiếm khi phản kháng Vương Lâm. Nó bị Vương Lâm quy về nhân quả và áp chế bằng Côn Cực Tiên.","detail":"Sau khi thoát khỏi túi trữ vật, Hứa Lập Quốc hóa thành đại kiếm giống tiên kiếm, mang kiếm khí sắc bén và viễn cổ kiếm ý lao tới. Vương Lâm cho rằng nhân của kiếm ý này là do mình tạo ra, nên quả phải thuộc về mình, khiến Hứa Lập Quốc bị vòng nhân quả của Côn Cực Tiên làm tan rã.","nguon":["@c0688"]},{"id":"hoa-ma-chi","name":"Hóa Ma Chỉ","cn":"","aliases":["Hóa Ma"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"chỉ pháp","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Hóa Ma Chỉ là một trong ba chỉ pháp của Vương Lâm được rà soát trước khi trùng kích cảnh giới cao hơn.","detail":"Ở chương này, Vương Lâm cảm thấy Hóa Ma cùng Tịch Diệt và Hoàng Tuyền đều chưa hoàn chỉnh, nếu tiếp tục theo hướng cũ sẽ bất lợi cho bước thứ ba, nên liên tục suy luận để điều chỉnh.","nguon":["@c0689"]},{"id":"ngung-hoa-tuyen-hon","name":"Ngưng Hóa Tuyền Hồn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Đạo niệm","phamCap":"tam thức Hoàng Tuyền","hePhai":"Sinh tử luân hồi ý cảnh","soHuu":["Vương Lâm"],"blurb":"Ngưng Hóa Tuyền Hồn là một trong tam thức đạo niệm Hoàng Tuyền của Vương Lâm.","detail":"Khi Vương Lâm hấp thu oán khí phàm nhân vào Hoàng Tuyền, thần thông này dần xuất hiện bóng dáng Tuyền Hồn, liên hệ trực tiếp với hướng ngưng tụ Tuyền Hồn.","nguon":["@c0689"]},{"id":"ao-thuat-cua-hua-lap-quoc","name":"Ảo thuật của Hứa Lập Quốc","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thuật mê hoặc","phamCap":"không rõ","hePhai":"Hứa Lập Quốc","soHuu":["Hứa Lập Quốc"],"blurb":"Ảo thuật Hứa Lập Quốc dùng để dụ tu sĩ bên ngoài phạm vi Hoành Vân Phong.","detail":"Trong lúc Vương Lâm bế quan, Hứa Lập Quốc dùng ảo thuật lừa vài tu sĩ vốn không dám tiến vào, trêu đùa một phen rồi thả đi, khiến họ về sau vẫn sợ hãi khi nhớ lại.","nguon":["@c0689"]},{"id":"tran-phap-tien-ngoc-o-hoang-mac-tay-bac-thanh-linh-tinh","name":"Trận pháp tiên ngọc ở hoang mạc tây bắc Thanh Linh Tinh","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp tu luyện","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Trận pháp do Vương Lâm bố trí bằng lượng lớn tiên ngọc để trùng kích Vấn Đỉnh viên mãn.","detail":"Tại hoang mạc tây bắc Thanh Linh Tinh, Vương Lâm sắp tiên ngọc thành trận pháp khổng lồ, ngồi trong trận thổ nạp tiên khí suốt một năm cho tới khi tiên ngọc cạn sạch.","nguon":["@c0689"]},{"id":"van-dinh-vien-man","name":"Vấn Đỉnh viên mãn","cn":"","aliases":["Vấn Đỉnh đại viên mãn"],"loai":"khac","loaiLabel":"Cảnh giới","phamCap":"bước tu đạo đầu tiên","hePhai":"tu chân","soHuu":["Vương Lâm"],"blurb":"Vấn Đỉnh viên mãn là trạng thái Vương Lâm đạt được sau mười chín năm tám tháng ở Thanh Linh Tinh.","detail":"Sau khi sinh tử luân hồi ý cảnh hoàn toàn viên mãn, Vương Lâm dùng trận pháp tiên ngọc và tiên dịch bổ sung tiên lực, chính thức đạt Vấn Đỉnh viên mãn, hoàn thành bước tu đạo đầu tiên của mình.","nguon":["@c0689"]},{"id":"am-hu","name":"Âm Hư","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cảnh giới","phamCap":"sau Vấn Đỉnh","hePhai":"tu chân","soHuu":[],"blurb":"Âm Hư là cảnh giới được Vương Lâm nghĩ tới sau khi đạt Vấn Đỉnh viên mãn.","detail":"Vương Lâm nhớ lời Cổ Yêu Bối La về thiên phạt của nghịch tu và tự hỏi khi đột phá khỏi Vấn Đỉnh tiến vào Âm Hư, thiên phạt có giáng xuống hay không.","nguon":["@c0689"]},{"id":"truu-linh-chi-lai","name":"Trừu Linh Chi Lai","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"cao cấp","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông rút khí tức tang thương từ Tiên Sơn, ngưng thành sương mù công kích.","detail":"Vương Lâm thi triển thông qua Tiên Sơn, khiến lão già Trương gia kinh hãi vì cho rằng tu sĩ Vấn Đỉnh đại viên mãn không thể dùng được thần thông bực này.","nguon":["@c0690"]},{"id":"hac-hoa-than-thong","name":"Hắc hỏa thần thông","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Trương gia","soHuu":["Lão già Trương gia"],"blurb":"Thuật tạo ngọn lửa màu đen để bao phủ, ngăn cản địch thủ.","detail":"Lão già Trương gia dùng hắc hỏa đối phó khôi lỗi Tiên Vệ khi bị Vương Lâm ép giao Lôi Đỉnh.","nguon":["@c0690"]},{"id":"khien-lua","name":"Khiên lửa","cn":"","loai":"than-thong","loaiLabel":"Phòng ngự thuật","phamCap":"không rõ","hePhai":"Trương gia","soHuu":["Lão già Trương gia"],"blurb":"Thuật phòng ngự tạo khiên lửa trước người.","detail":"Lão già Trương gia dùng để chắn khôi lỗi Tiên Vệ, nhưng bị một quyền đánh nứt rồi vỡ.","nguon":["@c0690"]},{"id":"loi-dien-thuc-chat-hoa","name":"Lôi điện thực chất hóa","cn":"","loai":"than-thong","loaiLabel":"Thần thông lôi hệ","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Lôi quang được ngưng tụ thành dạng thực chất trong tay.","detail":"Vương Lâm ngưng tụ lôi quang trong tay phải, dẫn tiếng sấm từ tinh không và hình thành một đạo lôi điện thực chất hóa để nối tiếp thế công.","nguon":["@c0690"]},{"id":"de-tam-nhan","name":"Đệ Tam Nhãn","cn":"","loai":"than-thong","loaiLabel":"Thần thông gia tộc","phamCap":"cao cấp","hePhai":"Gia tộc của lão già Âm Hư","soHuu":["Lão già Trương gia","Vương Lâm"],"blurb":"Thần thông mở mắt thứ ba ở giữa lông mày, phát hồng quang có thể làm tan rã hồn phách Tiên Sơn.","detail":"Lão già Trương gia là người đầu tiên trong gia tộc luyện thành thuật này. Vương Lâm nhận ra nó ẩn chứa một chút phương hướng bước thứ ba và khí tức quay về căn nguyên nên đổi ba thuật lấy ngọc giản, rồi tự tu chỉnh các chỗ sai.","nguon":["@c0691"]},{"id":"sat-luc-tien-quyet","name":"Sát Lục Tiên Quyết","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"cao cấp","hePhai":"","soHuu":["Vương Lâm","Lão già Trương gia"],"blurb":"Thuật dùng kiếm khí giết chóc đoạt sinh cơ, ngưng thành Sinh Chi Lạc Ấn.","detail":"Vương Lâm học từ tiền bối Toái Niết bước thứ hai và dùng làm mồi trao đổi Đệ Tam Nhãn. Thuật vừa có lực công kích vừa có khả năng phòng hộ bằng dấu ấn sinh cơ, nhưng Vương Lâm cảnh báo không nên tích Sát Lục Chi Khí quá mười vạn.","nguon":["@c0691"]},{"id":"sinh-chi-lac-an","name":"Sinh Chi Lạc Ấn","cn":"","loai":"than-thong","loaiLabel":"Ấn phòng hộ","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Dấu ấn sinh cơ do Sát Lục Tiên Quyết ngưng thành.","detail":"Sau khi kiếm khí giết chóc đoạt sinh cơ, sức sống hóa thành dấu ấn bao quanh thân thể. Số lượng càng nhiều thì phòng hộ càng vững, nhưng tích quá nhiều có thể nguy hiểm.","nguon":["@c0691"]},{"id":"dao-hon","name":"Đạo hồn","cn":"","loai":"khac","loaiLabel":"Thần hồn liên hệ","phamCap":"không rõ","hePhai":"","soHuu":["Thân Công Hổ"],"blurb":"Liên hệ thần hồn khiến Thân Công Hổ bị xem là đạo hồn không đầy đủ.","detail":"Đường Ngôn Phong dùng tình trạng đạo hồn để mỉa mai Thân Công Hổ. Chính đạo hồn này giúp Thân Công Hổ cảm nhận được một tia khí tức Tôn Chủ trong sao băng lôi đình.","nguon":["@c0693"]},{"id":"phan-than-thu-cua","name":"Phân thân thử cửa","cn":"","loai":"than-thong","loaiLabel":"Thần thông phân thân","phamCap":"không rõ","hePhai":"","soHuu":["Tu sĩ Âm Hư thả phân thân"],"blurb":"Thần thông tách phân thân dùng để dò xét cửa Lôi Tiên Giới.","detail":"Một tu sĩ Âm Hư dùng phân thân chạm vào sấm sét đỏ sậm trước cửa Lôi Tiên Giới; phân thân lập tức tan vỡ và khiến bản thể bị tia chớp truy diệt.","nguon":["@c0693"]},{"id":"hoa-thanh-vo-so-tinh-diem","name":"Hóa thành vô số tinh điểm","cn":"","loai":"than-thong","loaiLabel":"Thân pháp biến hóa","phamCap":"không rõ","hePhai":"","soHuu":["Lão già tóc bạc trong Lôi Tiên Giới"],"blurb":"Cách biến mất bằng vô số tinh điểm, kèm khí tức quay về căn nguyên.","detail":"Lão già tóc bạc trong Lôi Tiên Giới thi triển trên lôi sơn đen sau khi cảm ứng dị biến từ xa.","nguon":["@c0693"]},{"id":"than-thong-giam-cam-bun-dat","name":"Thần thông giam cầm bùn đất","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"cao cấp","hePhai":"","soHuu":["Lão già tóc bạc trong Lôi Tiên Giới"],"blurb":"Thần thông khiến bùn đất chứa thiên địa nguyên lực, phong tỏa đường thoát dưới lòng đất.","detail":"Sau khi Vương Lâm rơi xuống, khu vực quanh thạch thất bị lực lượng này giam cầm. Hắn không thể xuyên qua bùn đất ra ngoài, chỉ còn lối phía trước dẫn vào thông đạo bị điều khiển.","nguon":["@c0694"]},{"id":"than-thong-xuyen-qua","name":"Thần thông xuyên qua","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Năng lực xuyên qua bùn đất hoặc vật cản mà Vương Lâm vốn định dùng để thoát ra.","detail":"Trong thạch thất dưới lòng đất Lôi Tiên Giới, Vương Lâm thử dùng năng lực này nhưng bị bùn đất chứa thiên địa nguyên lực bắn ngược trở lại.","nguon":["@c0694"]},{"id":"than-thong-cua-ra-trong-thong-dao","name":"Thần thông cửa ra trong thông đạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi Tiên Giới","soHuu":["Lão giả tóc bạc"],"blurb":"Thần thông giam khốn trong hệ thống thông đạo dưới lòng đất ở Lôi Tiên Giới, tạo cửa ra xuất hiện theo thời gian và vị trí đặc thù. Dù thông đạo vật lý bị phá sập, mạng thiên địa nguyên lực vẫn duy trì cơ chế sinh cửa.","detail":"Cửa ra trong thông đạo bị người điều khiển, nhiều lần hiện trước mắt Vương Lâm rồi biến mất khiến hắn không thể rời đi ngay. Sau khi Vương Lâm phá sập hệ thống bùn đất, các tia thiên địa nguyên lực vẫn đan rậm như mạng lưới; tại những điểm giao nhau, cửa ra vẫn tiếp tục hình thành, cho thấy cốt lõi thần thông không nằm ở địa hình mà ở mạng nguyên lực.","nguon":["@c0695"]},{"id":"loi-uy-trong-nguyen-than-cua-vuong-lam","name":"Lôi uy trong nguyên thần của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông/lực lượng","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Lực lượng lôi uy nằm trong nguyên thần của Vương Lâm, được hắn vận cùng tiên lực khi phá thông đạo dưới đất. Khi xuất thủ, lôi uy ngưng thành tia chớp trong tay để phối hợp với Lôi Thú và Tiên Vệ.","detail":"Trong lúc phá cục giam khốn, Vương Lâm bắt quyết, vận tiên lực và lôi uy trong nguyên thần, ngưng tụ lôi điện để đánh vào cùng điểm mà Lôi Thú, Tiên Vệ và tiên kiếm đang công kích. Lực lượng này góp phần làm một thông đạo vỡ ra rồi kéo theo phản ứng dây chuyền khiến hệ thống thông đạo tan nát.","nguon":["@c0695"]},{"id":"la-thien-dai-tran","name":"La Thiên đại trận","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"La Thiên","soHuu":["Lão giả tóc trắng"],"blurb":"La Thiên đại trận là trận pháp trọng tâm trong kế hoạch mấy vạn năm của lão giả tóc trắng. Ông định bố trí đại trận sau khi thu được hồn của tiên sơn trong Lôi tiên giới.","detail":"Lão giả tóc trắng tạm bỏ qua chuyện Vương Lâm thoát sớm để tập trung thu hồn tiên sơn và bố trí La Thiên đại trận. Kế hoạch này được ông xem là bước then chốt giúp mình trở thành đệ nhất La Thiên tinh vực và quét ngang Liên Minh Tinh Vực.","nguon":["@c0696"]},{"id":"ma-cong-cua-hua-phong-han","name":"Ma công của Hứa Phong Hàn","cn":"","aliases":["Ma công của thanh niên áo tím"],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Hứa Phong Hàn"],"blurb":"Ma công của Hứa Phong Hàn tạo ma khí, ma diễm và ma ảnh đầu một sừng. Trong giao chiến, công pháp này còn điều khiển nước mưa hóa thành tên nước và trường thương nước mang ma khí.","detail":"Hứa Phong Hàn xuất hiện trong cầu vồng đen, toàn thân ma khí dày đặc và đứng trên ma ảnh đầu một sừng. Khi giao chiến với Vương Lâm, hắn dùng ma khí phối hợp mưa hóa thành mũi tên nước, màn nước và trường thương nước, về sau còn dùng Ma Thôn để cho ma ảnh nuốt lôi cầu.","nguon":["@c0696"]},{"id":"ma-thon","name":"Ma Thôn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Hứa Phong Hàn"],"blurb":"Ma Thôn là thần thông của Hứa Phong Hàn, khiến ma ảnh đầu một sừng mở ma khẩu để thôn phệ công kích. Nó được dùng để nuốt lôi cầu màu lam của Vương Lâm.","detail":"Trong trận giao thủ, Hứa Phong Hàn bắt quyết và quát Ma Thôn, khiến vết nứt trên ma ảnh mở rộng như ma khẩu. Ma khẩu này lập tức nuốt chửng lôi cầu do Vương Lâm ngưng tụ từ lôi uy và lôi lực Lôi tiên giới.","nguon":["@c0696"]},{"id":"loi-phap-cua-vuong-lam","name":"Lôi pháp của Vương Lâm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Lôi pháp của Vương Lâm vận chuyển nguyên thần, dẫn lôi uy và lôi lực trong Lôi tiên giới để ngưng tụ công kích. Chương này hắn dùng lôi cầu màu lam phá mưa tên ma khí và đánh về phía Hứa Phong Hàn.","detail":"Đứng trong Lôi tiên giới, Vương Lâm có thể mượn lôi lực dồi dào nơi đây để ngưng lôi cầu màu lam. Lôi pháp này giúp hắn phá tan mưa tên nước chứa sát khí, đồng thời buộc Hứa Phong Hàn phải dùng Ma Thôn để thôn phệ lôi cầu.","nguon":["@c0696"]},{"id":"loi-bao","name":"Lôi, bạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lôi pháp","soHuu":["Vương Lâm"],"blurb":"Lôi, bạo là thủ đoạn Vương Lâm dùng để dẫn nổ lôi cầu đã bị ma ảnh nuốt vào.","detail":"Trong trận với Hứa Phong Hàn, Vương Lâm quát lệnh khiến lôi cầu chưa bị hóa giải bộc phát từ trong cơ thể ma ảnh, làm ma ảnh màu đen tan nát trong lôi quang.","nguon":["@c0697"]},{"id":"dong-lam-chi-mac","name":"Đông Lâm chi mạc","cn":"","loai":"than-thong","loaiLabel":"Thần thông phòng ngự","phamCap":"không rõ","hePhai":"Ma công Âm Hư","soHuu":["Hứa Phong Hàn"],"blurb":"Đông Lâm chi mạc là thần thông phòng ngự Hứa Phong Hàn dùng trong khoảnh khắc nguy cơ sinh tử.","detail":"Hứa Phong Hàn phun nguyên thần tinh huyết chứa thiên địa nguyên lực, hóa thành màn sương máu trước người để chặn một quyền đỉnh phong của Tiên Vệ. Va chạm khiến đại lục chấn động, Tiên Vệ bị đẩy lùi và suy giảm kim quang.","nguon":["@c0697"]},{"id":"dao-niem-hoa-ma","name":"Đạo niệm hóa ma","cn":"","loai":"than-thong","loaiLabel":"Đạo niệm thần thông","phamCap":"Âm Hư","hePhai":"Ma đạo","soHuu":["Hứa Phong Hàn"],"blurb":"Đạo niệm hóa ma là biến hóa đạo niệm thuộc cảnh giới Âm Hư của Hứa Phong Hàn.","detail":"Hứa Phong Hàn dùng đạo niệm hóa ma để triển khai Ma Liên, đưa trận chiến với Vương Lâm từ tầng pháp bảo và thần thông sang đối kháng đạo niệm ngưng thật.","nguon":["@c0697"]},{"id":"dao-hoa-ma-lien-de-nhat-chuyen","name":"Đạo hóa Ma Liên, đệ nhất chuyển","cn":"","loai":"than-thong","loaiLabel":"Đạo niệm thần thông","phamCap":"Âm Hư","hePhai":"Ma đạo","soHuu":["Hứa Phong Hàn"],"blurb":"Đạo hóa Ma Liên, đệ nhất chuyển là đạo niệm thần thông chủ lực của Hứa Phong Hàn trong trận với Vương Lâm.","detail":"Hứa Phong Hàn khiến Ma Liên trên không xoay chuyển, ma diễm như thay thế thiên địa và tạo áp lực xóa diệt đối phương. Thần thông này trực tiếp đối đầu Hoàng Tuyền do Vương Lâm ngưng hiện.","nguon":["@c0697"]},{"id":"ma-diem-dot","name":"Ma diễm, đốt","cn":"","loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"không rõ","hePhai":"Ma đạo","soHuu":["Hứa Phong Hàn"],"blurb":"Ma diễm, đốt là đòn công kích Hứa Phong Hàn thúc phát từ Ma Liên.","detail":"Sau khi Ma Liên xoay chuyển, Hứa Phong Hàn thúc dòng xoáy ma diễm lao về phía Vương Lâm, kéo theo cuồng phong nóng rực và ép Vương Lâm thi triển Thức thứ hai.","nguon":["@c0697"]},{"id":"thuc-thu-hai-ngung-tu-tuyen-hon","name":"Thức thứ hai, ngưng tụ tuyền hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Hoàng Tuyền","soHuu":["Vương Lâm"],"blurb":"Thức thứ hai, ngưng tụ tuyền hồn là chiêu Vương Lâm dùng khi ma diễm áp sát.","detail":"Trong đạo niệm chi chiến, Vương Lâm thi triển thức này khiến Hoàng Tuyền rung động, oán khí bên trong điên cuồng ngưng tụ để đối phó ma diễm của Hứa Phong Hàn.","nguon":["@c0697"]},{"id":"ma-lien-bach-chuyen","name":"Ma Liên, bách chuyển","cn":"","loai":"than-thong","loaiLabel":"Thần thông đạo niệm","phamCap":"Không rõ","hePhai":"","soHuu":["Hứa Phong Hàn"],"blurb":"Thần thông đạo niệm của Hứa Phong Hàn, dùng Ma Liên xoay chuyển để áp chế đối thủ.","detail":"Hứa Phong Hàn thi triển khiến liên hoa xoay chuyển, tạo cảm giác thiên địa đảo lộn và ép thân thể Vương Lâm phải lùi. Khi gặp Hoàng Tuyền lực, tốc độ xoay chuyển của Ma Liên bị lực hút khổng lồ làm chậm lại.","nguon":["@c0698"]},{"id":"roi-nhan-qua","name":"Roi nhân quả","cn":"","aliases":["Nhân quả Côn Cực Tiên"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông từ mi tâm của Vương Lâm, đánh vào sơ hở tâm thần đối phương.","detail":"Vương Lâm triệu ra roi dài từ mi tâm, đánh cách không vào Hứa Phong Hàn. Một roi khiến thân thể Hứa Phong Hàn run rẩy, tâm thần bị ý niệm hỗn tạp xé rách và đạo niệm trở nên bất ổn.","nguon":["@c0698"]},{"id":"nguyen-hoa-ma-than","name":"Nguyên Hóa Ma Thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông nguyên lực","phamCap":"Không rõ","hePhai":"","soHuu":["Hứa Phong Hàn"],"blurb":"Thần thông nguyên lực ngưng ma diễm thành ma vật một sừng.","detail":"Sau khi bại trong chiến đạo niệm, Hứa Phong Hàn vận thiên địa nguyên lực, ngưng tụ ma diễm đen giữa hai tay thành ma vật một sừng giống tán ma nhưng yếu hơn. Ma vật vừa hiện ra đã quay lại cắn vai và nuốt chính Hứa Phong Hàn.","nguon":["@c0698"]},{"id":"con-mat-thu-ba","name":"Con mắt thứ ba","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông ở mi tâm của Vương Lâm, phát hồng mang khi đối diện nguy cơ.","detail":"Khi Hứa Phong Hàn thi triển Nguyên Hóa Ma Thần, Vương Lâm cảm nhận nguy hiểm, đặt tay trái lên mi tâm và mở con mắt thứ ba. Hồng mang trong mắt ngưng tụ không tan, nhưng ma vật đã quay lại nuốt Hứa Phong Hàn trước khi Vương Lâm xuất thủ rõ ràng.","nguon":["@c0698"]},{"id":"dao-niem-tao-khong-gian-tru-vat","name":"Đạo niệm tạo không gian trữ vật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Đạo niệm","soHuu":["Hứa Phong Hàn"],"blurb":"Thần thông dùng đạo niệm biến thành không gian chứa đồ, thay thế túi trữ vật thông thường.","detail":"Vương Lâm phát hiện Ma Liên không chỉ là đạo niệm thực thể mà còn là không gian chứa vật quý. Cách dùng đạo niệm làm túi trữ vật có năng lực bảo vệ mạnh, giải thích vì sao Hứa Phong Hàn không mang túi trữ vật bên ngoài.","nguon":["@c0699"]},{"id":"nang-luc-nuot-hon","name":"Năng lực nuốt hồn","cn":"","loai":"khac","loaiLabel":"Năng lực nguyên thần","phamCap":"không rõ","hePhai":"Nuốt hồn","soHuu":["Vương Lâm"],"blurb":"Năng lực nguyên thần đặc thù giúp Vương Lâm nuốt ma hồn trong Ma Liên.","detail":"Nhờ căn cơ nuốt hồn năm xưa, Vương Lâm có thể nuốt ma hồn mà tu sĩ tầm thường khó xử lý nếu không tu ma đạo công pháp. Việc nuốt ma hồn giúp nguyên lực của hắn phục hồi hoàn toàn và còn tinh tiến.","nguon":["@c0699"]},{"id":"tran-phap-cam-che-du-tu-si","name":"Trận pháp cấm chế dụ tu sĩ","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"không rõ","hePhai":"Cấm chế","soHuu":["Lý Nguyên","Nữ tu mắt phượng"],"blurb":"Cấm chế bẫy được bố trí kín trên đại lục vỡ trong Lôi Tiên Giới, hòa lẫn núi đá và dùng tiên lực làm mồi. Bề ngoài để lộ sơ hở khiến tu sĩ tưởng có thể phá trận và tiến vào cửa động bên dưới.","detail":"Trận pháp có phạm vi nhỏ, che giấu cửa động và phối hợp với tồn tại trong hang để săn tu sĩ. Sơ hở tiên lực không dung hợp hoàn toàn khiến Vương Lâm nghi ngờ đây là bố cục cố ý, còn tu sĩ trung niên dùng hình nhân mộc linh phá cấm thì lập tức bị dẫn vào cửa động và gặp nạn.","nguon":["@c0700"]},{"id":"muoi-tam-cam-che-lien-hoan","name":"Mười tám cấm chế liên hoàn","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế công kích","phamCap":"không rõ","hePhai":"Cấm chế","soHuu":["Lý Nguyên"],"blurb":"Thủ đoạn cấm chế do Lý Nguyên thi triển khi đối đầu Vương Lâm. Mười tám đạo cấm chế chồng lớp liên kết với nhau, biến hóa quỷ dị trong chiến đấu.","detail":"Lý Nguyên vung tay tạo tàn ảnh cấm chế, hợp thành mười tám đạo cấm chế liên hoàn. Vương Lâm nhận ra nếu phá giải đơn thuần sẽ tốn thời gian, nên chọn dùng lôi quang ngưng thành chưởng ấn hư ảo đánh thẳng vào hệ cấm chế này.","nguon":["@c0700"]},{"id":"loi-dinh-tu-ngon-tro-vuong-lam","name":"Lôi đình từ ngón trỏ Vương Lâm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông lôi pháp","phamCap":"không rõ","hePhai":"Lôi pháp","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn lôi pháp Vương Lâm phóng ra từ ngón trỏ tay phải. Một đạo lôi đình đánh tan lông chim pháp bảo của nữ tu, khiến nàng chịu phản chấn thổ huyết.","detail":"Khi nữ tu dùng quạt lông công kích, Vương Lâm không né tránh mà bước tới, đưa tay phải điểm ra. Lôi quang từ ngón trỏ bùng lên, trực tiếp phá hủy lông chim mang sát khí và làm chủ nhân pháp bảo bị thương.","nguon":["@c0700"]},{"id":"chuong-an-loi-quang-hu-ao","name":"Chưởng ấn lôi quang hư ảo","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông lôi pháp","phamCap":"không rõ","hePhai":"Lôi pháp","soHuu":["Vương Lâm"],"blurb":"Lôi quang được Vương Lâm ngưng thành chưởng ấn hư ảo để phá cấm chế trong lúc giao chiến. Thủ đoạn này dùng sức lôi đình trực diện thay vì chậm rãi phá giải cấm chế.","detail":"Đối diện mười tám cấm chế liên hoàn của Lý Nguyên, Vương Lâm nhận định đây là chiến đấu nên không cần phá giải từng bước. Hắn ngưng lôi quang thành chưởng ấn hư ảo, đánh thẳng vào cấm chế chồng lớp.","nguon":["@c0700"]},{"id":"cam-che-an-giau-than-hinh-cua-ly-nguyen","name":"Cấm chế ẩn giấu thân hình của Lý Nguyên","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Cấm chế của Lý Nguyên","soHuu":["Lý Nguyên","Vương Lâm"],"blurb":"Phương pháp cấm chế giúp ẩn giấu thân hình, được Lý Nguyên in vào ngọc giản giao cho Vương Lâm.","detail":"Vương Lâm yêu cầu Lý Nguyên giao ra phương pháp cấm chế ẩn giấu thân hình. Khi xem ngọc giản, hắn nhận ra hệ cấm chế này khác với tiên cấm thuật quen thuộc và chưa thể hiểu rõ ngay.","nguon":["@c0701"]},{"id":"thuat-cam-che-muoi-tam-pho-tuong","name":"Thuật cấm chế mười tám pho tượng","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Cấm chế của Lý Nguyên","soHuu":["Lý Nguyên","Vương Lâm"],"blurb":"Thuật cấm chế trong ngọc giản khiến tâm thần Vương Lâm hiện ra mười tám pho tượng lớn lồng vào nhau.","detail":"Khi Vương Lâm xem kỹ ngọc giản của Lý Nguyên, trong đầu hiện ra mười tám pho tượng lớn, mỗi pho tượng lại có một pho tượng khác bên trong, tạo cảm giác khác hẳn hệ tiên cấm hắn từng biết.","nguon":["@c0701"]},{"id":"cam-che-thien-cap-trung-pham","name":"Cấm chế thiên cấp trung phẩm","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"thiên cấp trung phẩm","hePhai":"cấm chế","soHuu":[],"blurb":"Cấm chế khổng lồ được Lý Nguyên nhận định ở trước đường đi trong Lôi Tiên Giới. Nó lấy lôi uy của Lôi Tiên Giới làm nền móng và vượt xa khả năng phá giải chắc chắn của hắn.","detail":"Trước đám sương mù tiên khí vô biên chắn đường, Lý Nguyên dùng la bàn tính toán nhưng la bàn nổ tung thành tro bụi. Sau đó hắn xác định đây là cấm chế thiên cấp trung phẩm, gồm vô số tổ hợp, lấy Lôi Tiên Giới làm nền, dùng nhiều điểm vững chắc cùng hồn linh vật làm cấm nhãn để hình thành đại trận luyện hóa vạn vật.","nguon":["@c0702"]},{"id":"diet-tuyet-dai-tran","name":"Diệt tuyệt đại trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"cấm chế","soHuu":[],"blurb":"Đại trận do cấm chế thiên cấp trung phẩm hình thành trong Lôi Tiên Giới. Theo Lý Nguyên, trận này có thể luyện hóa vạn vật trong trời đất.","detail":"Diệt tuyệt đại trận lấy lôi uy của Lôi Tiên Giới làm nền móng, dùng chín nghìn chín trăm chín mươi chín điểm vững chắc làm kết cấu và hồn linh vật làm cấm nhãn. Lý Nguyên nhận ra quy mô của nó sau khi la bàn tính toán cấm chế nổ tung, cho thấy trận pháp này vượt xa cấm chế thông thường.","nguon":["@c0702"]},{"id":"dao-nguoc","name":"Đảo ngược","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lão già chủ Lôi tiên giới cầm Lôi quang thiết liên","soHuu":["Lão già chủ Lôi tiên giới cầm Lôi quang thiết liên"],"blurb":"Thần thông không gian của lão già Lôi tiên giới, đảo lộn phương hướng trong khoảnh khắc. Vương Lâm đang bỏ chạy bị kéo ngược về trước mặt lão, không còn cách phản kháng.","detail":"Lão già vỗ nhẹ vào không trung, khiến không gian vặn vẹo như bị kéo giãn thành nhiều gợn sóng rồi hô Đảo ngược. Toàn bộ phương hướng trong không trung đảo lộn, Vương Lâm vốn đã dùng thần thông bỏ chạy liền bị lùi trở về cách lão ba trượng, tư thế vẫn như lúc đang chạy.","nguon":["@c0703"]},{"id":"than-thong-bo-chay-mau-huyet-hoc-o-yeu-linh","name":"Thần thông bỏ chạy máu huyết học ở Yêu Linh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Mảnh đất Yêu Linh","soHuu":["Vương Lâm"],"blurb":"Thần thông bỏ chạy Vương Lâm từng học ở mảnh đất Yêu Linh, vận dụng máu huyết tạo thành vòng tuần hoàn để thuấn di thoát thân. Trong chương này hắn dùng nó để thoát khỏi trảo định thân của lão già.","detail":"Khi bị trảo của lão già khóa cứng thân thể, Vương Lâm cắn chót lưỡi, nuốt giọt máu ẩn chứa tiên lực rồi vận dụng máu huyết trong người tạo thành một vòng tuần hoàn. Thần thông giúp hắn biến mất ngay trước khoảnh khắc bị bắt, nhưng sau đó vẫn bị Đảo ngược kéo trở lại.","nguon":["@c0703"]},{"id":"cam-che-tren-mi-tam-cua-ly-nguyen","name":"Cấm chế trên mi tâm của Lý Nguyên","cn":"","loai":"than-thong","loaiLabel":"Cấm chế thần thông","phamCap":"không rõ","hePhai":"Cấm chế","soHuu":["Lý Nguyên"],"blurb":"Cấm chế ở mi tâm giúp Lý Nguyên vận dụng thần thức quan sát trạng thái của Vương Lâm trong hành trình trên đại lục Lôi tiên giới.","detail":"Trong lúc phi hành, Lý Nguyên dùng ánh sáng cấm chế ở mi tâm để theo dõi biến hóa trong thân thể Vương Lâm. Hắn nhận định tu vi Vương Lâm càng cao càng có lợi cho chuyến đi, nhưng nếu đạt tới Âm Dương hư thực thì sẽ phát sinh biến số.","nguon":["@c0704"]},{"id":"cam-che-can-tim","name":"Cấm chế cần tìm","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"Cấm chế","soHuu":["Lý Nguyên"],"blurb":"Mục tiêu cấm chế mà Lý Nguyên dẫn Vương Lâm và Cát Hồng tìm kiếm trên đại lục trong Lôi tiên giới.","detail":"Sau khi tới trung tâm đại lục và đối chiếu địa hình với ký ức, Lý Nguyên xác định cấm chế không nằm tại chỗ đó mà đại khái ở phía đông. Hành trình tiếp tục thêm ba tháng, cuối cùng dừng trước ngọn núi cao vút trong mây mà hắn xác nhận là nơi cần tìm.","nguon":["@c0704"]},{"id":"mai-hoa-thuat","name":"Mai hoa thuật","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"Cấm chế cổ đã thất truyền","hePhai":"Truyền thừa Mai hoa thuật","soHuu":["Lý Nguyên"],"blurb":"Mai hoa thuật là cấm chế cổ nổi danh, có dấu vết từng xuất hiện trong tiên phủ ở mảnh đất Yêu Linh. Vương Lâm nhận ra dấu hiệu của nó trên cấm chế của Lý Nguyên và yêu cầu lấy pháp môn này làm thù lao.","detail":"Mai hoa thuật có danh tiếng rất lớn trong cấm chế cổ, tồn tại phân nhánh và quy củ truyền thừa nghiêm ngặt. Theo hiểu biết của Vương Lâm, người ngoài không thể tùy tiện học, đệ tử đích hệ cũng chỉ học được một phần, còn đầy đủ nhất thuộc về chưởng môn; vì vậy khi Lý Nguyên lộ phản ứng trước lời thăm dò, Vương Lâm xác nhận hắn thi triển đúng là Mai hoa thuật.","nguon":["@c0705"]},{"id":"cam-che-tren-ngon-nui-vo-danh","name":"Cấm chế trên ngọn núi vô danh","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Lý Nguyên"],"blurb":"Hệ thống cấm chế bao phủ ngọn núi vô danh trong Lôi tiên giới, từng bị người đời trước phá bớt qua nhiều lần Lôi tiên giới mở ra. Dù vậy ngọn núi vẫn mang sức hạn chế khiến Lý Nguyên dùng nó để gây sức ép với Vương Lâm.","detail":"Ngọn núi vô danh có nhiều lớp cấm chế phủ kín, không phải tự nhiên có đường lên núi mà là do người dò xét các đời trước dần bài trừ một phần. Lý Nguyên dựa vào địa thế và cấm chế nơi này để nói rằng Vương Lâm đã bước lên núi thì không thể tự rời đi nếu không được cho phép.","nguon":["@c0705"]},{"id":"mai-hoa-thap-tam-cam","name":"Mai hoa thập tam cấm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm thuật","phamCap":"thuộc Mai Hoa thuật","hePhai":"cấm chế","soHuu":["Lý Nguyên","Vương Lâm"],"blurb":"Mai hoa thập tam cấm là phần đầu của Mai Hoa thuật được Lý Nguyên giao cho Vương Lâm trong ngọc giản. Nội dung gồm mười ba hình ảnh lớn và mười ba đóa hoa mai, ẩn chứa quy tắc cấm chế.","detail":"Lý Nguyên lấy ngọc giản từ túi trữ vật giao cho Vương Lâm, nói bên trong có Mai hoa thập tam cấm. Đây là phần đầu của Mai Hoa thuật, còn năm loại khác được hắn hẹn giao sau khi vào núi.","nguon":["@c0706"]},{"id":"tu-dai-cam-thuat","name":"Tứ đại cấm thuật","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm thuật cấp Hư","phamCap":"cấp Hư","hePhai":"cấm chế","soHuu":[],"blurb":"Tứ đại cấm thuật là cấp độ cấm chế trên Thiên, Địa, Huyền, Hoàng. Lý Nguyên nói ngọn núi trước mặt do tứ đại cấm thuật tan vỡ mà tạo thành.","detail":"Trong lời giảng của Lý Nguyên, phía trên bốn cấp Thiên, Địa, Huyền, Hoàng còn có cấp Hư, gồm tứ đại cấm thuật. Ngọn núi không có điểm cuối trước mặt Vương Lâm là sản phẩm do tứ đại cấm thuật tan vỡ tạo nên.","nguon":["@c0706"]},{"id":"cap-cam-che-thien-dia-huyen-hoang","name":"Cấp cấm chế Thiên/Địa/Huyền/Hoàng","cn":"","aliases":["Thiên Địa Huyền Hoàng"],"loai":"khac","loaiLabel":"Phân cấp cấm chế","phamCap":"bốn cấp cơ bản","hePhai":"cấm chế","soHuu":[],"blurb":"Thiên, Địa, Huyền, Hoàng là bốn cấp phân chia cấm chế được Lý Nguyên giải thích trên đường lên núi. Chúng thấp hơn cấp Hư và tứ đại cấm thuật.","detail":"Lý Nguyên nói cấm chế ban đầu bắt nguồn từ quy tắc trời đất, lâu ngày được phân chia thành Thiên, Địa, Huyền, Hoàng. Trên bốn cấp này còn có một cấp độ khác là Hư.","nguon":["@c0706"]},{"id":"hoa-gia","name":"Hóa giả","cn":"","aliases":["Phương pháp hóa giả"],"loai":"khac","loaiLabel":"Phương pháp phá giải cấm chế","phamCap":"không rõ","hePhai":"cấm chế","soHuu":["Lý Nguyên"],"blurb":"Hóa giả là phương pháp hóa giải cần dùng để tìm tòi và nhìn thấu ngọn núi cấm thuật. Lý Nguyên cho rằng nếu không có cách hóa giả chính xác thì không thể thấy hết ngọn núi trong mây mù.","detail":"Khi giải thích lai lịch ngọn núi, Lý Nguyên nhấn mạnh người không biết phương pháp hóa giả sẽ không thể tìm tòi toàn bộ ngọn núi, bởi nơi này do tứ đại cấm thuật tan vỡ tạo nên và không có điểm cuối theo cách nhìn thông thường.","nguon":["@c0706"]},{"id":"an-quyet-tren-canh-tay-phai-tuong-da","name":"Ấn quyết trên cánh tay phải tượng đá","cn":"","aliases":["Ấn quyết trên tượng đá"],"loai":"khac","loaiLabel":"Ấn quyết cấm chế","phamCap":"không rõ","hePhai":"cấm chế","soHuu":["Chủ nhân của Lý Nguyên"],"blurb":"Ấn quyết phức tạp nằm trên cánh tay phải tượng đá ở đỉnh núi. Khi Vương Lâm nhìn kỹ, tâm thần hắn chấn động và bị kéo vào huyễn cảnh chiến trường Tiên giới.","detail":"Trên tượng đá trung niên nam tử ở đỉnh núi có ấn quyết phức tạp. Vương Lâm vừa nhìn thấy ấn quyết này thì tinh thần chấn động, tầm mắt tối lại và hắn chứng kiến cảnh tiên nhân lôi điện giao chiến cùng thanh bảo kiếm tím.","nguon":["@c0706"]}]};
